                created_at TEXT NOT NULL,
                updated_at TEXT NOT NULL
            );
INSERT INTO "knowledge_items" VALUES('182921b8-110a-41c3-b341-bbc4de58bc1c','plot','宗门大比','宗门大比·经典模板','## 核心结构
1. **赛前铺垫**：主角被人看不起，对手嚣张挑衅
2. **初赛惊艳**：主角低调出场，首轮轻松碾压弱敌，引起关注
3. **中期波折**：遇到强敌或暗算，陷入危机
4. **逆转爆发**：关键时刻突破/觉醒/使用底牌，反杀
5. **决赛登顶**：击败种子选手，一鸣惊人

## 常见变体
- 替人出战型：替师姐/好友出头
- 赌约型：输了要交出XX，赢了获得XX
- 暗流涌动型：大比只是表面，背后有势力博弈
- 天骄聚首型：各大势力天才齐聚，群雄争霸

## 关键爽点
- 扮猪吃虎，观众震惊
- 一招制敌，解说分析
- 对手装逼被打脸
- 赢得美人/宝物/名额','["战斗", "比武", "扮猪吃虎"]',1,'2026-04-12T06:47:15.780342+00:00','2026-04-12T06:47:15.780342+00:00');
INSERT INTO "knowledge_items" VALUES('c1290f21-7932-4337-bca0-69832bf5e9e2','plot','秘境探险','秘境探险·经典模板','## 核心结构
1. **秘境开启**：远古秘境/遗迹开启，各方势力争抢名额
2. **初入险境**：进入后遭遇天然险阻（禁制、阵法、凶兽）
3. **机缘获取**：主角凭借特殊能力/系统发现隐藏区域，获得核心机缘
4. **人心险恶**：其他探险者联手围攻主角，抢夺宝物
5. **秘境崩塌**：触发终极机关，秘境即将崩毁，逃生大战

## 常见机缘
- 远古强者传承（功法、记忆、武器）
- 天材地宝（灵果、矿脉、泉水）
- 契约灵兽
- 空间法宝
- 上古阵图/丹方

## 冲突设计
- 与敌对势力弟子在秘境内的生死搏杀
- 同行队友的背叛
- NPC守护者的考验','["探险", "机缘", "宝物"]',1,'2026-04-12T06:47:15.780342+00:00','2026-04-12T06:47:15.780342+00:00');
INSERT INTO "knowledge_items" VALUES('453851ac-cabd-46a2-9e23-13c0c2e656d2','plot','复仇','复仇线·经典模板','## 核心结构
1. **仇恨种子**：家族被灭/师门被毁/至亲被害，主角侥幸存活
2. **隐忍蛰伏**：实力不足，隐姓埋名修炼，暗中调查真相
3. **逐步揭秘**：发现仇人背后有更大势力，仇恨层层加深
4. **力量积累**：获得机缘不断变强，逐一清除仇人爪牙
5. **终极对决**：正面对决大仇人，真相大白，恩怨了结

## 写作要点
- 仇恨要合理，不能为仇而仇
- 复仇过程中要有成长和领悟
- 仇人不能太弱，要让读者觉得困难
- 可以设计反转（仇人也有苦衷/被利用）
- 复仇不是终点，要有更高的追求','["复仇", "成长", "隐忍"]',1,'2026-04-12T06:47:15.780342+00:00','2026-04-12T06:47:15.780342+00:00');
INSERT INTO "knowledge_items" VALUES('822cff3e-4fe6-467e-a0ec-e309dd51b25d','plot','拍卖会','拍卖会·经典模板','## 核心结构
1. **拍卖预热**：得知某珍稀物品即将拍卖，主角决定参与
2. **暗中准备**：筹集灵石/准备交换物品
3. **竞拍博弈**：与各方势力竞价，展示财力和底蕴
4. **意外收获**：以独特眼光识破被人忽略的宝物（鉴定系统特别适用）
5. **散场冲突**：出场后被人盯上，截杀抢宝

## 爽点设计
- 别人不认识的宝物主角一眼看出价值
- 用极低价格拍下逆天宝物
- 土豪打脸：对手志在必得，主角加价到底
- 拍卖后反杀截道之人','["拍卖", "竞价", "鉴宝"]',1,'2026-04-12T06:47:15.780342+00:00','2026-04-12T06:47:15.780342+00:00');
INSERT INTO "knowledge_items" VALUES('5f870e10-c94d-47c0-8440-bfad7f19403d','plot','证道飞升','证道飞升·终局模板','## 核心结构
1. **天劫降临**：修为到达极致，引动天地劫雷
2. **渡劫过程**：九九天劫层层递进，每道比前一道强十倍
3. **心魔考验**：劫雷中夹杂心魔劫，回顾一生执念
4. **最终突破**：粉碎心魔，肉身重塑，元神蜕变
5. **飞升离去**：仙门开启，告别故人，飞升上界

## 渡劫场景描写要点
- 天地异象：风云变色、百兽朝拜、天花乱坠
- 劫雷描写：颜色递进（金→紫→黑→混沌色）
- 身体变化：经脉重塑、骨骼再造、元神凝实
- 情感高潮：走马灯式回忆、对故人的不舍','["渡劫", "飞升", "终局", "高潮"]',1,'2026-04-12T06:47:15.780342+00:00','2026-04-12T06:47:15.780342+00:00');
INSERT INTO "knowledge_items" VALUES('27fcdd19-800e-49a8-a936-1db6891b8c3b','character','废柴逆袭','废柴逆袭型主角','## 核心特征
- 初始被所有人看不起，资质平庸或有缺陷
- 性格坚韧不屈，不服输
- 获得外挂后厚积薄发，一飞冲天

## 常见设定
- 天生废脉/灵根碎裂 → 获得系统修复
- 家族弃子 → 逆袭后回归打脸
- 宗门杂役弟子 → 大比中一鸣惊人

## 性格模板
- 表面老实低调，内心坚定执着
- 记仇但不滥杀，恩怨分明
- 对帮助过自己的人极度忠诚
- 逐渐展现领袖气质

## 成长弧光
废柴 → 初露锋芒 → 扬名立万 → 称霸一方 → 天下无敌','["主角", "逆袭", "成长"]',1,'2026-04-12T06:47:15.780342+00:00','2026-04-12T06:47:15.780342+00:00');
INSERT INTO "knowledge_items" VALUES('9179a795-922f-46e1-ab79-72e7862fba41','character','天才型','天纵奇才型主角','## 核心特征
- 天赋异禀，悟性超群
- 自信但不自大，有大格局
- 前期碾压同辈，后期挑战越级

## 常见设定
- 天生异象/特殊体质（混沌体、万灵根等）
- 幼年便展现惊人天赋
- 被大能看中收为弟子

## 性格模板
- 从容不迫，气度非凡
- 对弱者温和，对强敌无惧
- 有自己的道心和坚持
- 重感情，愿意为朋友赴汤蹈火

## 挑战设计
- 天才的敌人是更大的天才
- 天道嫉妒，劫难更重
- 树大招风，被各方针对','["主角", "天才", "碾压"]',1,'2026-04-12T06:47:15.780342+00:00','2026-04-12T06:47:15.780342+00:00');
INSERT INTO "knowledge_items" VALUES('17b67599-1981-4f39-b3e8-41cd374c89ff','character','重生型','重生型主角','## 核心特征
- 前世修炼巅峰被害/失败，重生回到过去
- 拥有前世记忆和经验
- 知道未来大事件的走向

## 优势利用
- 提前布局，抢夺前世错过的机缘
- 规避前世的陷阱和背叛
- 以低境界展现高境界的见识和手段

## 冲突来源
- 重生改变了命运轨迹，蝴蝶效应导致未知变数
- 前世的仇人提前注意到主角
- 有些悲剧即使重生也无法阻止

## 常见剧情线
- 前世欠下的情债今生偿还
- 收服前世的对手为己用
- 改写家族/宗门被灭的命运','["主角", "重生", "先知"]',1,'2026-04-12T06:47:15.780342+00:00','2026-04-12T06:47:15.780342+00:00');
INSERT INTO "knowledge_items" VALUES('85697b2b-e6ed-4da0-adcf-46dfb912200f','character','反派模板','经典反派类型','## 类型一：世家纨绔
- 仗势欺人，出身高贵
- 作用：前期送经验，打脸对象
- 结局：被主角碾压后家族道歉

## 类型二：天骄宿敌
- 与主角实力相当的同辈天才
- 有自己的骄傲和坚持
- 多次交手，互有胜负，最终败于主角

## 类型三：幕后黑手
- 实力深不可测的老怪物
- 布局千年的阴谋家
- 对主角的威胁是渐进式揭露的

## 类型四：亦正亦邪
- 有自己的苦衷和理由
- 让读者又恨又同情
- 最终或被感化或壮烈收场

## 反派写作要点
- 反派要有动机，不能纯粹为恶
- 反派要有能力，不能太蠢
- 反派倒下的时机要恰到好处','["反派", "对手", "冲突"]',1,'2026-04-12T06:47:15.780342+00:00','2026-04-12T06:47:15.780342+00:00');
INSERT INTO "knowledge_items" VALUES('e8adf621-062a-40c8-8b2d-9265fd82552e','character','红颜知己','女性角色·红颜知己模板','## 类型一：青梅竹马
- 从小一起长大，默默守护
- 在主角最低谷时不离不弃

## 类型二：高冷师姐
- 初期冷淡，被主角的才华/品格打动
- 有自己的实力和追求

## 类型三：敌对阵营
- 身份对立但互相吸引
- 制造情感张力和剧情冲突

## 类型四：亦师亦友
- 实力在主角之上，给予指引
- 关系从师徒发展为并肩作战

## 写作要点
- 每个女性角色要有独立人格和故事线
- 不能只是花瓶，要有自己的成长
- 感情发展要有铺垫，不能突兀','["女主", "感情线", "配角"]',1,'2026-04-12T06:47:15.780342+00:00','2026-04-12T06:47:15.780342+00:00');
INSERT INTO "knowledge_items" VALUES('001396a8-f732-48cc-80d9-dc0bdeba4d3b','world','修炼体系','经典九境修炼体系','## 标准境界
1. **练气期**（1-9层）：引气入体，感应天地灵气
2. **筑基期**（初/中/后/大圆满）：凝聚灵力根基，脱胎换骨
3. **金丹期**：丹田凝结金丹，寿元大增（500年）
4. **元婴期**：金丹化为元婴，可神魂出窍
5. **化神期**：元婴化神，掌握空间法则初步
6. **合体期**：神魂与肉身完美融合
7. **大乘期**：接触天道法则，为渡劫做准备
8. **渡劫期**：承受天劫洗礼，脱胎成仙
9. **真仙**：飞升上界，踏入仙道

## 每境突破条件
- 修炼资源（灵石、丹药、天材地宝）
- 战斗感悟（生死间的顿悟）
- 心境提升（道心圆满）
- 特殊机缘（传承、秘境）

## 战力标准
- 每大境界碾压下一境界
- 同境界内以功法、法宝、战斗经验决胜
- 天才可越级挑战（通常1-2个小境界）','["境界", "修炼", "体系"]',1,'2026-04-12T06:47:15.780342+00:00','2026-04-12T06:47:15.780342+00:00');
INSERT INTO "knowledge_items" VALUES('69e8ff22-bb48-422f-9c92-498fcad2c060','world','宗门设定','宗门势力体系','## 宗门等级
- **圣地/帝级宗门**：有仙人级别老祖坐镇，统御一域
- **一流宗门**：大乘期掌教，弟子数万
- **二流宗门**：合体期掌教，弟子数千
- **三流宗门**：元婴期掌教，弟子数百
- **小门派**：金丹期掌门，弟子数十

## 宗门架构
- 掌教/宗主
- 长老会（太上长老、护法长老、客卿长老）
- 峰主/堂主
- 内门弟子 → 外门弟子 → 记名弟子 → 杂役弟子

## 宗门资源
- 灵脉等级决定宗门底蕴
- 功法传承是核心竞争力
- 丹药供给、法宝铸造能力
- 秘境数量和品质','["宗门", "势力", "架构"]',1,'2026-04-12T06:47:15.780342+00:00','2026-04-12T06:47:15.780342+00:00');
INSERT INTO "knowledge_items" VALUES('5054f7a5-87ff-42b7-98c7-ef7edcca6563','world','天材地宝','天材地宝分级体系','## 灵草分级
- 凡级：百年灵草，练气期使用
- 灵级：千年灵草，筑基金丹使用
- 宝级：万年灵草，元婴化神使用
- 圣级：十万年灵草，合体大乘使用
- 仙级：百万年灵草，渡劫仙人使用

## 矿石分级
- 玄铁 → 秘银 → 紫金 → 星辰石 → 混沌石

## 丹药体系
- 聚灵丹（练气）→ 筑基丹 → 凝丹丹 → 破境丹 → 化神丹
- 疗伤：回春丹 → 续命丹 → 再生丹
- 辅助：洗髓丹、易容丹、隐息丹

## 法宝等级
- 法器 → 灵器 → 宝器 → 圣器 → 仙器 → 混沌至宝','["宝物", "丹药", "法宝", "等级"]',1,'2026-04-12T06:47:15.780342+00:00','2026-04-12T06:47:15.780342+00:00');
INSERT INTO "knowledge_items" VALUES('e6ece5bd-aa0a-424d-8e2e-4e5ce67886cb','world','地理设定','修仙世界地理体系','## 地域划分
- **凡人界**：灵气稀薄，凡人与低阶修士共存
- **修真界**：灵气充沛，各大宗门林立
- **上界/仙界**：渡劫飞升后到达的更高世界
- **域外战场**：抵御域外天魔的边境

## 特殊地域
- **秘境**：远古强者开辟的独立空间
- **禁地**：极度危险但机缘丰厚之地
- **灵脉**：灵气汇聚之地，宗门必争
- **绝地**：各种极端环境（极寒之地、炼狱火域、万毒沼泽）

## 地域与实力对应
- 东域（练气-金丹为主）→ 中域（元婴-化神为主）→ 上界（合体以上）','["地理", "地图", "区域"]',1,'2026-04-12T06:47:15.780342+00:00','2026-04-12T06:47:15.780342+00:00');
INSERT INTO "knowledge_items" VALUES('c0f29e12-b1f4-4d87-96ea-39d9baeaa3d9','satisfying','打脸','经典打脸套路集','## 套路一：拍卖会打脸
对手："区区一个XX境的穷鬼也敢来竞价？"
主角淡淡加价，直接翻倍，全场震惊。

## 套路二：炼丹打脸
对手炼制了自认为极品的丹药炫耀，主角随手炼出更高品质的，还是带丹纹的。

## 套路三：战斗打脸
"我一根手指就能碾死你"→主角一招秒杀。旁观者："这...这不可能！"

## 套路四：身份打脸
对手嚣张跋扈欺压主角，突然来了更大的人物对主角毕恭毕敬。"原来他是XX大人的......"

## 套路五：鉴宝打脸
别人当废品丢掉的东西被主角捡起，鉴定后发现是逆天神物。

## 打脸写作公式
铺垫嘲讽(1-2段) → 蓄势(半段) → 反转一击(1段) → 震惊反应(1-2段) → 对手面如死灰(半段)','["打脸", "爽点", "反转"]',1,'2026-04-12T06:47:15.780342+00:00','2026-04-12T06:47:15.780342+00:00');
INSERT INTO "knowledge_items" VALUES('598f0332-3ffe-4bfe-8352-f638b2d571ff','satisfying','突破','修炼突破·爽点描写模板','## 突破场景公式
1. **蓄势阶段**：灵气汇聚，天地异象初现
2. **瓶颈碰撞**：多次冲击关卡，痛苦挣扎
3. **关键契机**：顿悟/丹药/外力催动，打破瓶颈
4. **破境瞬间**：轰然突破，体内翻天覆地的变化
5. **实力暴涨**：新境界的力量感知，碾压性提升

## 描写模板
"丹田中的灵力如同决堤的洪水，沿着经脉奔涌而出。每一寸肌肤、每一根骨骼都在这股力量的洗礼下重塑。他能清晰地感受到，自己与天地之间的联系在这一刻变得前所未有的紧密——突破了！"

## 天地异象参考
- 练气→筑基：光柱冲天，方圆百里灵气涌动
- 金丹→元婴：雷云聚集，天降祥瑞
- 化神→合体：空间裂缝，法则显现
- 渡劫→真仙：九天神雷，万物朝拜','["突破", "修炼", "爽点"]',1,'2026-04-12T06:47:15.780342+00:00','2026-04-12T06:47:15.780342+00:00');
INSERT INTO "knowledge_items" VALUES('1d4260f5-a651-4e45-b03d-00f249d62dab','satisfying','系统奖励','系统奖励·爽点描写模板','## 签到系统奖励
"【叮！恭喜宿主在太虚剑宗签到成功！】
【奖励：太虚剑诀（天级上品）×1、太虚纯阳丹×3、灵石×10000】
【特殊奖励：太虚剑意传承（直接领悟入门级太虚剑意）】"

## 奖励层层递进
- 普通签到 → 稀有签到 → 隐藏签到 → SSR级签到
- 每次奖励要比上次更震撼
- 偶尔给个"谢谢参与"让读者哭笑不得

## 系统升级爽点
- 系统商城刷新出逆天物品
- 隐藏任务触发，奖励翻十倍
- 成就系统解锁新功能

## 写作要点
- 奖励要实用，不能只看着爽用不上
- 频率控制，太频繁会审美疲劳
- 与剧情结合，在需要时恰好获得关键奖励','["系统", "奖励", "签到", "爽点"]',1,'2026-04-12T06:47:15.780342+00:00','2026-04-12T06:47:15.780342+00:00');
INSERT INTO "knowledge_items" VALUES('d8ee9ae8-407a-4aba-8689-7ce0f5b36d49','foreshadow','身世伏笔','身世之谜伏笔模板','## 埋设手法
- 主角身上有来历不明的玉佩/胎记/体质
- 路人NPC看到主角时神色异样
- 某些功法主角学起来异常轻松（血脉契合）
- 大能偶遇主角后若有所思

## 回收节奏
- 第一次暗示（10%进度）：不经意提到，读者可能忽略
- 第二次加深（30%进度）：主角开始怀疑自己身世
- 第三次接近真相（50%进度）：发现关键线索
- 真相揭露（70%进度）：身世大白，伴随剧情高潮

## 常见身世设定
- 远古神族后裔
- 被封印的大能转世
- 上界贬落凡间的天才
- 两大对立势力的联姻之子','["伏笔", "身世", "悬念"]',1,'2026-04-12T06:47:15.780342+00:00','2026-04-12T06:47:15.780342+00:00');
INSERT INTO "knowledge_items" VALUES('bd128f97-9922-4efc-84de-766b33818904','foreshadow','物品伏笔','关键道具伏笔模板','## 埋设手法
- 早期获得看似普通的物品，无法鉴定
- 物品在特定情况下发出微弱反应
- 有人出高价购买被主角拒绝
- 古籍中记载了类似物品的传说

## 回收方式
- 危急时刻物品自动激活救主
- 到达特定地点触发共鸣，解锁物品真实形态
- 集齐其他碎片后合一
- 境界提升后才能驾驭

## 经典案例
- 破旧储物戒指实际是混沌至宝
- 小时候捡到的石头是远古神兽蛋
- 传家之宝是上古阵图碎片
- 随身玉佩封印着前辈残魂','["伏笔", "道具", "法宝"]',1,'2026-04-12T06:47:15.780342+00:00','2026-04-12T06:47:15.780342+00:00');
INSERT INTO "knowledge_items" VALUES('d96fe480-5855-4512-b82a-a3f9a2892037','foreshadow','人物伏笔','人物关系伏笔模板','## 埋设手法
- 配角偶尔展现与身份不符的见识/实力
- 某人对主角态度异常（过度关注或刻意疏远）
- 两个看似无关的角色有相似的习惯/特征
- 反派阵营中有人暗中帮助主角

## 常见伏笔
- 路边的乞丐实际是隐世强者
- 师父有不为人知的过去
- 好友的真实身份是敌方卧底
- 死去的亲人其实还活着

## 回收要点
- 铺垫要自然，回收要震撼
- 真相揭露时读者恍然大悟："原来如此！"
- 前文的"不合理"之处全部得到解释','["伏笔", "人物", "反转"]',1,'2026-04-12T06:47:15.780342+00:00','2026-04-12T06:47:15.780342+00:00');
INSERT INTO "knowledge_items" VALUES('37c97526-5c0b-4824-9dbd-bf12fabaef24','chapter_template','战斗章','战斗章·写作模板','## 结构
1. **战前对峙**（200字）：双方亮相，气势碰撞，对话中透露矛盾根源
2. **试探交手**（300字）：各出一招试探实力，建立战力参照
3. **攻防拉锯**（500字）：互有来回，展示各自功法特色
4. **危机时刻**（300字）：主角陷入劣势或受伤
5. **逆转爆发**（400字）：底牌尽出，绝地反击
6. **一锤定音**（200字）：决定性一击，胜负已分
7. **战后余波**（100字）：旁观者反应，收获总结

## 描写技巧
- 用环境描写烘托战斗激烈程度（大地碎裂、云层翻涌）
- 穿插对手/旁观者的心理活动增强层次感
- 功法招式要有画面感，不能只是"一拳打出"
- 战斗节奏要有快有慢，不能全程高潮','["战斗", "模板", "节奏"]',1,'2026-04-12T06:47:15.780342+00:00','2026-04-12T06:47:15.780342+00:00');
INSERT INTO "knowledge_items" VALUES('644525d2-152c-4d1f-b012-7d679292018a','chapter_template','修炼章','修炼章·写作模板','## 结构
1. **修炼契机**（200字）：获得新功法/资源，决定闭关
2. **修炼过程**（500字）：灵气运转，身体变化，瓶颈碰撞
3. **领悟升华**（300字）：对功法/大道的感悟，思想蜕变
4. **突破/收获**（300字）：实力提升，新能力觉醒
5. **出关检验**（200字）：测试新实力，与之前对比

## 避免枯燥的技巧
- 修炼中穿插回忆、领悟、与内心对话
- 通过体内的灵气变化来写画面感
- 外界同时发生的事件交叉叙述
- 突破时的天地异象渲染氛围
- 修炼中遭遇意外（走火入魔、被打扰、意外发现）','["修炼", "突破", "模板"]',1,'2026-04-12T06:47:15.780342+00:00','2026-04-12T06:47:15.780342+00:00');
INSERT INTO "knowledge_items" VALUES('169f1cd8-e088-4b51-80e1-4b2d0401cdba','chapter_template','剧情推进章','剧情推进章·写作模板','## 结构
1. **日常场景**（300字）：轻松的互动，展现人物关系
2. **信息引入**（200字）：得到新消息/任务/邀请
3. **分析决策**（200字）：主角思考利弊，做出选择
4. **行动准备**（200字）：整顿装备、告别、出发
5. **旅途见闻**（300字）：路上的所见所闻，世界观展示
6. **章末悬念**（100字）：到达目的地或遭遇意外，留下钩子

## 技巧
- 在日常中自然地埋设伏笔
- 通过对话推进信息，避免大段旁白
- 角色互动中展现性格和关系发展
- 每章结尾都要有一个"想看下一章"的理由','["剧情", "推进", "日常", "模板"]',1,'2026-04-12T06:47:15.780342+00:00','2026-04-12T06:47:15.780342+00:00');
INSERT INTO "knowledge_items" VALUES('1312c631-d0b1-4fcc-9259-630e12da4d0c','chapter_template','转折章','剧情转折章·写作模板','## 结构
1. **风平浪静**（200字）：一切看似正常/顺利
2. **不祥预兆**（200字）：细微的异常，读者隐隐不安
3. **突发事件**（300字）：灾难/背叛/强敌突然降临
4. **局势恶化**（400字）：连锁反应，情况急转直下
5. **绝境展现**（200字）：主角面临前所未有的困境
6. **希望微光**（100字）：在绝望中留下一线生机

## 写作要点
- 转折前的平静越多，转折的冲击越大
- 转折要合理，不能太突兀，前文要有铺垫
- 不要一次性把所有坏消息抛出，要层层叠加
- 留一线希望，不能让读者绝望到弃书','["转折", "高潮", "冲突", "模板"]',1,'2026-04-12T06:47:15.780342+00:00','2026-04-12T06:47:15.780342+00:00');
INSERT INTO "knowledge_items" VALUES('b98a7162-0fbb-40af-abcb-8a0c2fb092a6','chapter_template','搞笑日常章','轻松搞笑章·写作模板','## 适用场景
- 大战之后的休整期
- 紧张剧情之间的调节
- 展现角色可爱一面

## 常见桥段
- 系统抽奖抽到奇葩物品
- 主角做饭/炼丹翻车
- 灵兽/宠物的逗趣互动
- 误会导致的啼笑皆非场面
- 配角之间的拌嘴斗嘴

## 结构
1. 日常场景开端
2. 意外/误会发生
3. 连锁搞笑反应
4. 角色吐槽/自嘲
5. 温馨收尾（笑完之后的感动）

## 注意事项
- 搞笑要符合角色性格
- 不能影响角色在读者心中的形象
- 适度，不能连续多章都是日常','["搞笑", "日常", "轻松", "模板"]',1,'2026-04-12T06:47:15.780342+00:00','2026-04-12T06:47:15.780342+00:00');
INSERT INTO "knowledge_items" VALUES('b46665ce-6ff7-4531-b698-f5cd2e25da4e','plot','退婚流','退婚流·经典模板','## 核心结构
1. **婚约存在**：主角与某强势家族有婚约
2. **天才陨落**：主角因故变为废物（灵根碎裂、修为全失）
3. **被退婚辱**：对方上门退婚，言语极尽侮辱（"癞蛤蟆想吃天鹅肉"）
4. **立下誓言**："莫欺少年穷" / "三十年河东三十年河西"
5. **逆袭打脸**：获得金手指后快速崛起，再次相遇时碾压对方
6. **对方后悔**：退婚方追悔莫及，试图挽回被拒

## 源流
《斗破苍穹》奠定此流派基础，"三十年河东三十年河西，莫欺少年穷"成为经典名句。

## 写作要点
- 退婚场景要写得屈辱感强烈，激发读者的代入和愤怒
- 主角要隐忍而非暴怒，显得有格局
- 打脸要分阶段：先打小脸（同辈），再打大脸（对方长辈）
- 可以设置反转：退婚女方其实有苦衷/被逼迫

## 变体
- 正常退婚但男主借题发挥
- 女方退婚后发现男主才是真正天才
- 掌门流：收退婚流主角为徒','["退婚", "打脸", "逆袭", "开局"]',1,'2026-04-12T06:47:15.780342+00:00','2026-04-12T06:47:15.780342+00:00');
INSERT INTO "knowledge_items" VALUES('da71d796-fb28-4259-a973-82022beee0ff','plot','城门冲突','城门/酒楼冲突·经典模板','## 核心结构
1. **主角低调入城**：穿着朴素，修为内敛
2. **被人轻视**：守卫刁难/纨绔撞人/服务员冷眼
3. **小冲突**：对方嚣张至极，动手挑衅
4. **轻松化解**：主角一招制敌或展露身份
5. **背后势力**：纨绔搬救兵/找家族长辈
6. **连环打脸**：长辈到场反而对主角恭敬（认出身份/实力）

## 经典场景变体
- **城门收费**：守卫多收灵石→主角身份暴露→守卫跪下
- **酒楼争座**："这位置我们公子看上了"→强行打脸
- **坊市争购**：两人同时看上一件宝物→竞价→动手
- **客栈投宿**：店小二嫌主角穷→掌柜认出宝物→VIP待遇

## 爽点公式
轻视铺垫(2段) → 冲突升级(1段) → 一击碾压(1段) → 旁观者震惊(2段) → 后续连锁反应(1段)','["装逼", "打脸", "城门", "酒楼"]',1,'2026-04-12T06:47:15.780342+00:00','2026-04-12T06:47:15.780342+00:00');
INSERT INTO "knowledge_items" VALUES('3378924e-3674-451f-9a4a-f5f38877553e','plot','家族危机','家族危机·经典模板','## 核心结构
1. **离家修炼**：主角幼年离开家族外出修炼/被赶出
2. **家族遇难**：敌对势力欺压，逼迫交出产业/灵脉
3. **回归救援**：主角实力大成后回归
4. **试探较量**：先不暴露身份，观察形势
5. **一人镇场**：关键时刻出手，碾压对方
6. **认祖归宗**：家族长辈激动落泪，族人震惊

## 常见配置
- 家族大比中替本族天才出战
- 灵脉/矿脉争夺战中亮出底牌
- 仇敌上门逼婚/迫害时一人力挽狂澜

## 情感要素
- 亲情线：不被认可的少年终于得到长辈的认可
- 对比线：曾经看不起主角的族中长辈态度大转
- 成长线：从被庇护者变为守护者','["家族", "回归", "守护", "逆袭"]',1,'2026-04-12T06:47:15.780342+00:00','2026-04-12T06:47:15.780342+00:00');
INSERT INTO "knowledge_items" VALUES('0cf41c2e-fc68-4a5c-ab61-4c885fbd4ca2','plot','赌石鉴宝','赌石/鉴宝·经典模板','## 核心结构
1. **赌石场/地摊**：主角逛地摊/参加赌石大会
2. **慧眼识珠**：凭系统/灵识发现被忽略的宝物
3. **廉价买入**：用极低价格购得
4. **当众鉴定**：切开/鉴定后众人震惊
5. **价值爆表**：宝物价值远超买价百倍千倍
6. **引来觊觎**：有人出高价买/暗中跟踪抢夺

## 适用系统类型
- 鉴定系统：一眼看穿物品真实属性和价值
- 捡属性系统：别人丢弃的废料中含有稀有属性
- 透视/神识：直接看到石料内部结构

## 爽点设计
- 专家鉴定为废品 → 主角买下 → 切出逆天宝物 → 专家被打脸
- 对手花天价买入 → 切出垃圾 → 主角低价买入 → 切出极品','["鉴宝", "赌石", "捡漏", "爽点"]',1,'2026-04-12T06:47:15.780342+00:00','2026-04-12T06:47:15.780342+00:00');
INSERT INTO "knowledge_items" VALUES('0807b421-071b-4dc3-836a-0bdcbcbf0ffb','plot','天劫渡劫','天劫渡劫·高潮模板','## 天劫类型
- **小天劫**：元婴/化神修士每三百年经历一次
- **大天劫**：炼虚/合体/大乘修士每三千年一次
- **仙劫**：渡劫期飞升仙界时所渡

## 天劫等级
三九天劫（27道） → 六九天劫（54道） → 九九天劫（81道）

## 劫雷颜色递进
银白 → 金色 → 紫色 → 黑色 → 混沌色（五色交织）

## 核心结构
1. **劫云聚集**：方圆百里天色骤变，乌云翻滚
2. **第一波雷劫**：试探性雷电，主角轻松扛过
3. **逐步加强**：每一道比前一道强数倍
4. **危机时刻**：雷劫中夹杂心魔劫/有敌人趁机偷袭
5. **破釜沉舟**：主角在雷劫中领悟大道/以劫为引突破
6. **浴火重生**：劫后实力暴涨，肉身蜕变，元神升华

## 经典桥段
- 引来的天劫远超同境（天妒之劫）→ 侧面烘托主角天赋
- 敌人趁渡劫虚弱时偷袭 → 主角借天劫之力反杀
- 天劫无法劈死主角 → 天道震怒加量 → 仍然挡不住','["天劫", "渡劫", "突破", "高潮"]',1,'2026-04-12T06:47:15.780342+00:00','2026-04-12T06:47:15.780342+00:00');
INSERT INTO "knowledge_items" VALUES('bdc97a6e-aa8f-400d-a2b1-3fd90c4b5377','character','穿越者','穿越型主角','## 核心特征
- 现代灵魂穿越到修仙世界
- 拥有现代知识体系和思维方式
- 初期适应新世界，有认知优势但缺乏修炼常识

## 优势
- 化学/物理知识用于炼丹/炼器创新
- 现代管理思维用于宗门/家族经营
- 信息时代的思维方式：重视情报、善于分析
- 心理学知识用于揣摩人心

## 性格模板
- 前世社畜 → 穿越后追求自由
- 前世学霸 → 以科学思维理解修仙
- 前世军人 → 行事果断，擅长战略

## 常见冲突
- 现代价值观与修仙世界弱肉强食的碰撞
- 尝试改变不合理的制度/习俗
- 知道太多反而惹来杀身之祸','["主角", "穿越", "现代"]',1,'2026-04-12T06:47:15.780342+00:00','2026-04-12T06:47:15.780342+00:00');
INSERT INTO "knowledge_items" VALUES('67a42981-992e-44c7-bfa1-2e8900be21c9','character','智谋型配角','军师/智囊型配角','## 核心定位
战斗力不一定最强，但智谋超群，是主角团的大脑。

## 性格特征
- 喜欢算计，常说"一切尽在掌握"
- 外表儒雅/病弱，内心腹黑
- 对主角忠诚但有自己的底线

## 功能
- 为主角出谋划策，解决非战斗难题
- 分析敌人弱点，制定战术
- 在主角冲动时泼冷水

## 经典搭配
- 主角热血冲动 + 军师冷静理性
- 军师的计策不总是成功，偶尔也会翻车
- 军师有自己的秘密和过往

## 写作注意
- 不要让军师全知全能，那会削弱主角的光环
- 军师的智慧要通过具体的计策体现，不能只是嘴上说聪明','["配角", "智谋", "军师"]',1,'2026-04-12T06:47:15.780342+00:00','2026-04-12T06:47:15.780342+00:00');
INSERT INTO "knowledge_items" VALUES('0015dd01-44df-4602-874b-1999f032bad6','world','灵根体质','灵根与特殊体质大全','## 灵根分类

### 按属性
五行灵根：金、木、水、火、土
变异灵根：雷、冰、风、暗、光

### 按数量
- 伪灵根：四五种属性混杂，修炼极慢
- 真灵根：二三种属性，修炼较快
- 天灵根：单一属性，修炼速度数倍于常人，结丹无瓶颈

### 按品质
下品 → 中品 → 上品 → 极品灵根

## 经典特殊体质

### 强化类
- 荒古圣体：近战无敌，力量惊人
- 先天道体：天生契合大道，修炼速度极快
- 永恒仙体：恢复力惊人，战斗持久
- 混沌神体：蕴含混沌之力，攻防一体

### 元素类
- 天火焚体：与天地真火共鸣
- 太阴玄冰体：先天寒属性极致
- 雷灵体：引雷入体修炼
- 九阳神体：纯阳至刚

### 特殊类
- 吞噬之体：可吞噬他人修为
- 轮回之体：具前世记忆碎片
- 涅盘之体：濒死时可浴火重生
- 万毒不侵体：百毒不侵

### "废材"体质（后期逆天）
- 九阴绝脉：无法修炼→发现是远古神族后裔
- 全属性灵根：看似杂乱→实为可修万法
- 废灵根：被系统激活后质变','["灵根", "体质", "天赋", "设定"]',1,'2026-04-12T06:47:15.780342+00:00','2026-04-12T06:47:15.780342+00:00');
INSERT INTO "knowledge_items" VALUES('ead9c2fa-c5b7-4294-8b20-0ceb65793ad6','world','功法等级','功法与灵石等级体系','## 功法分级（两种常见体系）

### 体系一：颜色/材质分级
黄级（下/中/上） → 玄级 → 地级 → 天级 → 圣级 → 神级 → 混沌级

### 体系二：品级分级
一品（最低）→ 九品（最高）
或反序：九品（最低）→ 一品（最高）

### 体系三：星级
一星 → 九星（每星分初/中/后期）

## 灵石分级
下品灵石 → 中品灵石 → 上品灵石 → 极品灵石 → 仙晶
换算：1中品 = 100下品，1上品 = 100中品

## 阵法分级
聚灵阵（日常修炼）→ 护山大阵（宗门防御）→ 杀阵 → 困阵 → 幻阵 → 传送阵
品质：凡阵 → 灵阵 → 仙阵 → 神阵

## 符箓分级
低阶符箓（一次性）→ 中阶符箓 → 高阶符箓 → 仙符
用途：攻击符/防御符/辅助符/传讯符/禁制符','["功法", "灵石", "阵法", "等级"]',1,'2026-04-12T06:47:15.780342+00:00','2026-04-12T06:47:15.780342+00:00');
INSERT INTO "knowledge_items" VALUES('fcc4442b-f09e-4567-b779-9b6e2d8da44a','world','洪荒体系','洪荒流境界与法宝体系','## 境界体系
天仙 → 金仙 → 太乙金仙 → 大罗金仙 → 准圣（斩三尸） → 圣人（混元大罗金仙） → 天道

### 斩三尸
- 善尸：斩断善念执念
- 恶尸：斩断恶念执念
- 本尸（执念尸）：斩断最深执念

## 法宝分级
后天灵宝 → 先天灵宝（下品/中品/上品） → 先天至宝 → 造化之宝

## 经典先天至宝
- 盘古幡（元始天尊）：开天之力
- 太极图（太上老君）：攻防一体
- 诛仙四剑+诛仙阵图（通天教主）：最强杀阵
- 混沌钟（东皇太一）：时间之力
- 山河社稷图（女娲）：空间至宝
- 十二品灭世黑莲（冥河老祖）：防御至宝

## 核心概念
- 鸿蒙紫气：成圣之基，天地间仅有数道
- 功德：杀劫中获得，可用于突破/炼宝
- 气运：与天道挂钩，影响修炼和机缘
- 量劫：天道循环，每一纪会降下量劫','["洪荒", "圣人", "法宝", "先天至宝"]',1,'2026-04-12T06:47:15.780342+00:00','2026-04-12T06:47:15.780342+00:00');
INSERT INTO "knowledge_items" VALUES('61ab6bb9-f6da-4b72-beac-3221c7eaf0c7','satisfying','信息差碾压','信息不对称·爽点设计技巧','## 核心原理
读者知道主角拥有某个秘密能力/信息，但书中角色不知道，形成"看主角表演"的期待感。

## 典型场景

### 场景一：重生者的预知
主角知道秘境某处有隐藏宝物 → 别人盲目寻找 → 主角精准定位 → 众人惊叹

### 场景二：系统鉴定
拍卖会上一件无人出价的废品 → 系统显示真实属性是逆天神物 → 低价拍下 → 使用时全场震惊

### 场景三：隐藏修为
主角故意压制修为显示低境界 → 被人挑衅轻视 → 认真出手时降维打击

### 场景四：身份隐藏
主角就是传说中的XX大人/某某强者 → 以路人身份行走 → 关键时刻身份曝光 → 全场跪下

## 写作公式
建立认知（读者知道真相）→ 错误判断（角色误判主角）→ 行为反差（按错误判断行事）→ 真相揭露 → 震惊反转','["信息差", "爽点", "碾压", "反转"]',1,'2026-04-12T06:47:15.780342+00:00','2026-04-12T06:47:15.780342+00:00');
INSERT INTO "knowledge_items" VALUES('62e7d456-40ae-4180-b9b7-85e0f8088c45','satisfying','黄金三章','黄金三章·开篇爽点设计','## 什么是黄金三章
读者通常只给前三章（6000-10000字）的机会决定是否继续阅读。编辑签约也主要看前三章。

## 前三章必须完成的任务
1. 代入感：让读者迅速代入主角视角
2. 冲突/矛盾：第一章就必须有矛盾
3. 期待感（钩子）：让读者好奇后续
4. 金手指展示：展示主角的特殊之处
5. 世界观轮廓：简要交代设定（不超过3句）

## 结构模板
**第一章（3000字）**：直接进入场景冲突 → 主角处境（低谷/危机）→ 金手指出现 → 章末钩子
**第二章**：金手指初步使用 → 小爽点 → 更大矛盾出现 → 章末钩子
**第三章**：第一个小高潮（打脸/逆袭）→ 更大目标浮现 → 预示后续精彩

## 章末钩子万能公式
"当[主角]以为[情况A]时，[意外B]发生了。"

## 致命错误
- 大段世界观设定（前三章不要超过3句介绍设定）
- 流水账写日常（没有冲突）
- 主角太被动（前三章必须有主动行为和选择）
- 出场人物太多（控制在3-5个）
- 没有章末钩子','["开篇", "黄金三章", "钩子", "技巧"]',1,'2026-04-12T06:47:15.780342+00:00','2026-04-12T06:47:15.780342+00:00');
INSERT INTO "knowledge_items" VALUES('b07741e3-f7aa-46c6-bade-5f15ad223f63','satisfying','送菜流','送菜流·反派衬托技巧','## 核心机制
创造一个看似比主角更强/更幸运的角色，但他的所有好运最终都会转化为主角的收获。

## 运作方式
1. 反派/对手获得好处（宝物、美人、地位）
2. 读者看到后产生焦虑和不甘
3. 主角介入，夺走对方的一切
4. 读者获得双倍爽感（对手失去 + 主角获得）

## 实例
- 反派辛苦收集的材料 → 被主角一锅端
- 对手苦苦追求的女角 → 心甘情愿跟了主角
- 纨绔炫耀的法宝 → 打赌输给主角

## 注意事项
- "送菜"角色不能太蠢，要有一定实力和手段
- 频率不宜过高，否则显得刻意
- 送菜角色可以进化为真正的宿敌（从送菜到威胁）','["送菜", "反派", "衬托", "爽点"]',1,'2026-04-12T06:47:15.780342+00:00','2026-04-12T06:47:15.780342+00:00');
INSERT INTO "knowledge_items" VALUES('b4466fb6-d281-4e2a-969e-28fa05f82284','foreshadow','网文伏笔技巧','网文伏笔写作注意事项','## 网文伏笔 vs 传统小说伏笔

网文的伏笔必须比传统小说埋得更浅、更容易被发现。原因：
- 读者是碎片化阅读，间隔数天甚至数月
- 太深的伏笔会被遗忘，回收时读者没有"恍然大悟"的感觉
- 长时间未回收的伏笔在阅读中像是"啰嗦的累赘"

## 伏笔回收时机建议
- 短线伏笔：5-10章内回收（最安全）
- 中线伏笔：20-50章回收（需中途提醒1-2次）
- 长线伏笔：100章以上回收（必须每30章提醒一次）

## 提醒技巧
- 主角偶尔回想/触摸相关物品
- 配角提起相关话题
- 遇到类似情况时主角心中闪过疑问

## 常见伏笔类型
1. 物品伏笔：早期获得的不起眼物品后期关键
2. 人物伏笔：路人NPC后期身份揭晓
3. 事件伏笔：早期的不合理事件后期解释
4. 语言伏笔：某句看似随意的话后期应验
5. 数字/细节伏笔：特定数字或细节反复出现','["伏笔", "技巧", "回收", "网文"]',1,'2026-04-12T06:47:15.780342+00:00','2026-04-12T06:47:15.780342+00:00');
INSERT INTO "knowledge_items" VALUES('01089399-c85d-4cfe-ae0e-dd8a5f41545d','foreshadow','命运伏笔','命运预言伏笔模板','## 埋设手法
- 远古壁画/预言石碑记载了一段模糊的预言
- 算命老者/占卜师说出意味深长的话
- 天象异变暗示某个命运转折即将到来
- 主角做了一个似真似幻的梦

## 预言设计要点
- 语言要模糊，可以有多重解读
- 预言的字面意思和真实含义要有反差
- 读者以为预言指向A，实际指向B

## 回收示例
预言："混沌开天日，废体成神时"
- 前期理解：主角体质废物不可能成神
- 中期理解：主角体质被修复，似乎在应验
- 最终揭示：主角的"废体"本身就是混沌体，觉醒后直接成神

## 多层回收
第一次回收（30%）：应验一部分，读者以为已经用完
第二次回收（70%）：更深层含义浮现
第三次回收（结尾）：最终揭示完整真相','["伏笔", "预言", "命运", "反转"]',1,'2026-04-12T06:47:15.780342+00:00','2026-04-12T06:47:15.780342+00:00');
INSERT INTO "knowledge_items" VALUES('de9a97ee-a44e-4adf-ac8c-8af79d70e08b','chapter_template','开篇章','小说开篇第一章·模板','## 钩子式开头类型

### 类型一：倒叙震撼
"三年后我站在这座城市的废墟上，回想一切的起点——那不过是一条系统提示。"

### 类型二：冲突前置
直接进入被退婚/被追杀/被羞辱的场景，不做任何铺垫。

### 类型三：悬念钩
"他体内沉睡了十六年的东西，终于醒了。"

### 类型四：倒计时危机
"距离妖兽潮还有三天，而他的修为还停留在淬体一重。"

## 第一章结构（3000字）
1. **开篇50字**：建立场景和氛围（不要写背景！）
2. **前500字**：交代主角困境，让读者产生共情
3. **中间1500字**：冲突发生+金手指出现
4. **后1000字**：金手指初步展示效果
5. **最后50字**：章末钩子，制造悬念

## 绝对不要做的事
- 用一整段描述天气/景色开头
- "他从梦中惊醒"
- 大段介绍世界设定/历史背景
- 一上来介绍太多人物','["开篇", "第一章", "钩子", "模板"]',1,'2026-04-12T06:47:15.780342+00:00','2026-04-12T06:47:15.780342+00:00');
INSERT INTO "knowledge_items" VALUES('b3fc3c32-c68f-4aaf-9281-cd7619981366','chapter_template','战斗描写技巧','战斗描写·五感沉浸法','## 五感描写法

### 视觉
"一道赤红剑气撕裂夜幕，刺目的光芒在他视网膜上烧出一道残影。"

### 听觉
"拳头砸在护体真元上，发出闷雷般的轰响，震得他耳膜一阵刺痛。"

### 触觉
"一股寒意从剑伤处沿经脉蔓延，半边身子像是被冰封住。"

### 嗅觉
"空气中弥漫着烧焦皮肉的恶臭，混着泥土和铁锈的腥气。"

### 味觉
"一口腥甜涌上喉头，他硬生生咽了回去。"

## 招式描写四层法
1. **动作层**：身体怎么动
2. **能量层**：灵力如何运转
3. **效果层**：对环境/对手的影响
4. **感受层**：对手/旁观者的反应

好的招式描写 = 至少写到三层。

## 节奏控制
- 危急紧迫 → 短句+动词密集
- 大招蓄力 → 长句+环境渲染
- 一击定胜 → 突然慢镜头放大

## 旁观者视角增强震撼
"围观的筑基修士们只觉一股无形的压力从天而降，腿一软，直接跪在了地上。"

## 环境互动
打斗不要在真空中，让角色利用/破坏环境：山崩、湖水倒卷、树木断裂。','["战斗", "描写", "五感", "技巧"]',1,'2026-04-12T06:47:15.780342+00:00','2026-04-12T06:47:15.780342+00:00');
INSERT INTO "knowledge_items" VALUES('110e877a-783f-41da-8694-ed2879e88e64','chapter_template','系统流章节','系统流章节·写作模板','## 系统消息格式模板

### 签到系统
"【叮！恭喜宿主在[地点]签到成功！】
【奖励：[物品名]（[品级]）×1、[丹药名]×3、灵石×[数量]】
【当前签到进度：[X/Y]】"

### 任务系统
"【触发任务：[任务名]】
【任务描述：[描述]】
【任务奖励：[奖励]】
【时限：[时间]】
【惩罚：[惩罚]】"

### 商城系统
"【系统商城已刷新！】
【热销商品】[物品] - [价格]积分
【限时特惠】[物品] - [折扣价]积分（原价[价格]）
【当前积分：[数量]】"

## 系统流写法核心
- 系统奖励要与当前困境精准匹配（但不能太巧）
- 系统消息是调味品，不是主菜，控制出现频率
- 每3-5章设计一次系统升级/新功能解锁
- 系统要有限制（冷却时间/使用条件/积分不够）
- 系统可以有个性（毒舌系统/正经系统/吐槽系统）

## 两大模式
1. **传统系统流**：系统发任务→主角完成→获奖励（被动）
2. **新式系统流**：主角有目标→系统提供辅助工具（主动）

推荐第二种，主角更有主动性，读者爽感更强。','["系统", "签到", "任务", "商城", "模板"]',1,'2026-04-12T06:47:15.780342+00:00','2026-04-12T06:47:15.780342+00:00');
INSERT INTO "knowledge_items" VALUES('4a888e57-aefc-4bab-8162-cd1c5e90f91c','plot','师徒传承','师徒传承·经典模板','## 核心结构
1. **拜师入门**：主角因特殊机缘被隐世强者收为弟子
2. **严苛修炼**：师父以非常规方式训练，主角苦不堪言但进步飞速
3. **师父秘密**：逐渐发现师父有不为人知的过去和使命
4. **师徒分离**：师父因故离去/牺牲/被封印，留下遗物和未完成的任务
5. **继承衣钵**：主角以师父传承为基础走出自己的道

## 师父类型
- 邋遢老头型：看似不靠谱实则深藏不露
- 严厉型：打骂教育但内心关爱
- 亦师亦友型：平等相处，互相成就
- 残魂/器灵型：寄居在法宝中指导修炼

## 情感高潮设计
- 师父为保护弟子燃烧寿元
- 主角达到师父当年的境界时回忆往昔
- 最终超越师父时的感慨与传承','["师徒", "传承", "情感", "成长"]',1,'2026-04-13T08:39:52.545801+00:00','2026-04-13T08:39:52.545801+00:00');
INSERT INTO "knowledge_items" VALUES('e6bb8fa8-5811-40e7-a560-ab3714e2bda9','plot','势力争霸','势力争霸·经典模板','## 核心结构
1. **势力初建**：主角建立/接管一个弱小势力
2. **招兵买马**：收服人才，积累资源，发展壮大
3. **周边摩擦**：与邻近势力产生冲突，小规模战争
4. **强敌压境**：大势力注意到主角势力的崛起，施压打压
5. **绝地反击**：以弱胜强的关键战役，奠定地位
6. **称霸一方**：成为区域霸主，进入更大的舞台

## 势力发展节奏
小门派 → 一方势力 → 区域霸主 → 天下争锋

## 关键要素
- 内政：资源分配、人才培养、制度建设
- 外交：结盟、谈判、间谍战
- 战争：阵法对决、高手单挑、兵力调度
- 人心：收服桀骜不驯的强者、处理内部矛盾','["势力", "争霸", "建设", "战争"]',1,'2026-04-13T08:39:52.545801+00:00','2026-04-13T08:39:52.545801+00:00');
INSERT INTO "knowledge_items" VALUES('79d64a01-b6e7-42d2-8c46-002e258f9d46','plot','丹道大会','丹道/炼器大会·经典模板','## 核心结构
1. **大会召开**：各方炼丹师/炼器师齐聚，比拼技艺
2. **资格赛**：主角以低阶身份参赛，被人轻视
3. **惊艳全场**：炼制出超越预期的丹药/法宝
4. **暗中使绊**：对手暗中破坏主角的炼制过程
5. **绝境翻盘**：在材料被毁/炉鼎破裂的情况下依然成功
6. **夺魁封号**：获得大师称号，各方势力争相拉拢

## 爽点设计
- 别人炼废的材料主角捡起来炼成极品
- 一炉多丹，数量碾压
- 丹成异象（天降丹雷、丹香百里）
- 炼出失传已久的古方丹药

## 副线利用
- 通过大会结识重要人脉
- 获得稀有材料/古方作为奖励
- 为后续剧情埋下伏笔（某材料的来源引出秘境线索）','["炼丹", "炼器", "大会", "比试"]',1,'2026-04-13T08:39:52.545801+00:00','2026-04-13T08:39:52.545801+00:00');
INSERT INTO "knowledge_items" VALUES('f835b0e1-adbd-4103-80e7-a5f3178b67b2','plot','域外入侵','域外入侵·大事件模板','## 核心结构
1. **异象预兆**：天地灵气异变，空间裂缝频现
2. **先遣试探**：域外天魔小股入侵，低阶修士伤亡惨重
3. **各方联合**：原本敌对的势力被迫联手抵御外敌
4. **惨烈大战**：正面战场血战，高手陨落，防线告急
5. **主角破局**：主角发现天魔弱点或获得克制之法
6. **封印/击退**：付出巨大代价后暂时封印裂缝

## 叙事价值
- 打破原有势力格局，重新洗牌
- 制造"共同敌人"让对立角色合作
- 大量角色牺牲，提升故事厚重感
- 为后续"上界"剧情做铺垫

## 战争场面描写
- 万人修士阵法对决天魔大军
- 高手在天空中的神通碰撞
- 凡人城池被波及的惨状
- 老一辈强者燃烧寿元的悲壮','["域外", "入侵", "战争", "大事件"]',1,'2026-04-13T08:39:52.545801+00:00','2026-04-13T08:39:52.545801+00:00');
INSERT INTO "knowledge_items" VALUES('ac8ddf08-f23b-45cd-b766-a988bbb142a4','plot','轮回转世','轮回转世·经典模板','## 核心结构
1. **今生困境**：主角在当前世遇到无法解释的梦境/记忆碎片
2. **前世线索**：逐渐发现自己是某位大能的转世
3. **记忆觉醒**：在特定触发下恢复部分前世记忆和能力
4. **因果纠缠**：前世的恩怨在今生重演，前世仇人找上门
5. **超越前世**：不被前世束缚，走出属于自己的道

## 与重生流的区别
- 重生：同一个人回到过去，记忆完整
- 轮回：不同的人，前世记忆碎片化，性格可能不同

## 戏剧冲突
- 前世的爱人今生成了敌人
- 前世的弟子今生修为远超自己
- 前世未完成的执念成为今生的枷锁
- "我是前世的他，还是今生的我？"身份认同危机','["轮回", "转世", "前世", "身份"]',1,'2026-04-13T08:39:52.545801+00:00','2026-04-13T08:39:52.545801+00:00');
INSERT INTO "knowledge_items" VALUES('f8fffe83-cc7c-4bb8-b3eb-645031732f60','character','忠犬型配角','忠犬护主型配角','## 核心定位
从小跟随主角的忠诚伙伴，战斗力不如主角但绝对可靠。

## 性格特征
- 对主角死心塌地，不离不弃
- 有自己的底线和原则（不是无脑服从）
- 性格互补：主角冷静则他热血，主角冲动则他稳重

## 经典桥段
- 替主角挡致命一击
- 被敌人威胁利诱仍不背叛
- 在主角低谷时说出关键鼓励
- 独自断后让主角先走

## 成长弧光
- 从依附主角到独当一面
- 获得属于自己的机缘和突破
- 最终成为主角的左膀右臂

## 写作注意
- 不要让他永远当炮灰，要给他高光时刻
- 忠诚不等于没有个性，要有自己的目标
- 偶尔的意见分歧让关系更真实','["配角", "忠诚", "兄弟"]',1,'2026-04-13T08:39:52.545801+00:00','2026-04-13T08:39:52.545801+00:00');
INSERT INTO "knowledge_items" VALUES('500fb012-1f04-4dad-a5da-812903bc4f43','character','商人型配角','商人/消息贩子型配角','## 核心定位
游走各方势力之间的情报贩子或商人，亦正亦邪。

## 性格特征
- 唯利是图但讲规矩（买卖公平）
- 消息灵通，人脉广泛
- 说话滴水不漏，喜欢打哑谜
- 关键时刻会因为与主角的情分而破例

## 功能
- 为主角提供关键情报（收费）
- 帮助主角购买稀有资源
- 成为势力间的中间人
- 在主角被追杀时提供藏身之所

## 经典台词模板
"这条消息值一千灵石，看在老朋友面子上……八百。"
"我只卖消息，不卖命。但这次……算我欠你的。"

## 写作注意
- 不要让他变成全知全能的工具人
- 他的消息也有错误的时候
- 他有自己的利益诉求和底线','["配角", "商人", "情报", "人脉"]',1,'2026-04-13T08:39:52.545801+00:00','2026-04-13T08:39:52.545801+00:00');
INSERT INTO "knowledge_items" VALUES('0311c693-a137-4ae9-86b4-5160ab90e14e','character','师尊型角色','神秘师尊型角色','## 核心定位
引导主角修炼的导师级角色，实力深不可测。

## 类型划分
### 类型一：残魂导师
- 寄居在法宝/玉佩中的上古强者残魂
- 知识渊博但无法直接出手
- 随着主角变强逐渐恢复

### 类型二：隐世老怪
- 隐居深山/市井的超级强者
- 看似疯疯癫癫实则洞察一切
- 只在关键时刻点拨一二

### 类型三：系统化身
- 系统具象化的人格
- 从冷冰冰的AI逐渐发展出感情
- 最终与主角建立深厚羁绊

## 退场时机
师父/导师不能一直在，否则主角无法独立成长。
- 前期：手把手教学（1-20%进度）
- 中期：偶尔指点（20-50%进度）
- 后期：完全放手或已不在（50%以后）','["师父", "导师", "神秘", "成长"]',1,'2026-04-13T08:39:52.545801+00:00','2026-04-13T08:39:52.545801+00:00');
INSERT INTO "knowledge_items" VALUES('e2e4b262-1518-4103-8a6f-136303b77ca5','character','魔道反派','魔道/邪修大反派模板','## 核心特征
- 修炼禁忌功法，实力强大但代价巨大
- 有让读者理解（但不认同）的动机
- 行事不择手段但有自己的逻辑

## 常见动机
- 为救至亲不惜堕入魔道
- 被正道迫害后走上极端
- 追求长生不死的执念
- 要打破不公的修仙世界秩序

## 魅力塑造
- 给他一个让人同情的过去
- 对特定的人展现温柔一面
- 在与主角对决时说出发人深省的话
- "你觉得正道就真的正吗？"

## 与主角的关系设计
- 镜像对照：走了不同道路的同类人
- 理念对立：目的相似但手段截然不同
- 最终对决时双方都有成长和改变','["反派", "魔道", "邪修", "深度"]',1,'2026-04-13T08:39:52.545801+00:00','2026-04-13T08:39:52.545801+00:00');
INSERT INTO "knowledge_items" VALUES('9741207c-5f2a-4447-9ae7-7292e948496d','character','灵兽伙伴','灵兽/契约兽伙伴模板','## 核心定位
主角的动物伙伴，既是战力也是情感寄托。

## 经典灵兽类型
- 幼年神兽：初期弱小可爱，后期蜕变逆天
- 上古异种：有独特血脉和天赋
- 变异灵兽：普通物种发生变异
- 远古传承兽：携带前主人的记忆和功法

## 成长模式
蛋/幼兽 → 契约觉醒 → 血脉进化 → 返祖蜕变 → 神兽归位

## 互动设计
- 贪吃：对天材地宝有天然感应，吃了就进化
- 护主：主角危险时暴走
- 搞笑：日常中的憨态可掬
- 通灵：能感知主角情绪，关键时刻传递鼓励

## 写作注意
- 灵兽要有自己的性格，不是工具
- 战斗中灵兽与主角的配合要有策略
- 灵兽的成长线要与主角同步','["灵兽", "契约", "伙伴", "萌宠"]',1,'2026-04-13T08:39:52.545801+00:00','2026-04-13T08:39:52.545801+00:00');
INSERT INTO "knowledge_items" VALUES('857957a8-281f-4a32-a13e-1366ba70d571','world','禁地设定','十大禁地·模板','## 设计思路
每个修仙世界都需要几个让所有人闻风丧胆的禁地，作为冒险和机缘的终极场所。

## 经典禁地类型
1. **万妖岭**：妖兽横行，深处有远古妖皇沉睡
2. **死亡沙海**：无尽沙漠，空间混乱，有上古战场遗迹
3. **九幽冥渊**：通往冥界的裂缝，阴气极重，有鬼修势力
4. **混沌海域**：空间裂缝密布，偶有上界宝物坠落
5. **天劫遗址**：远古大能渡劫失败之地，残留恐怖雷力
6. **万毒瘴谷**：万毒之源，有绝世毒物也有解毒圣药
7. **时空乱流**：时间法则紊乱，可能加速或倒退
8. **血修战场**：上古血修大战遗址，血气冲天
9. **仙魔古战场**：仙魔大战遗迹，残留仙魔之力
10. **轮回秘境**：传说可窥探前世今生的神秘之地

## 禁地使用节奏
前期：只是传说中的存在，渲染恐怖
中期：主角实力足够，开始探索外围
后期：深入核心区域，获得核心机缘','["禁地", "秘境", "危险", "地图"]',1,'2026-04-13T08:39:52.545801+00:00','2026-04-13T08:39:52.545801+00:00');
INSERT INTO "knowledge_items" VALUES('aa4d741a-88c0-4b8f-9d47-7d1a40bd23cf','world','都市修仙设定','都市修仙·世界设定模板','## 核心设定
灵气复苏后的现代世界，科技与修仙并存。

## 社会结构
- 普通人：占99%，大部分不知道修仙者存在
- 觉醒者：灵气复苏后觉醒灵根的新修士
- 古修家族：隐藏在都市中的古老修仙世家
- 官方机构：政府设立的修仙管理部门（如"灵能局"）

## 核心矛盾
- 修仙者与普通人的共存问题
- 古修家族对新觉醒者的态度（打压/拉拢）
- 灵气复苏带来的异变（灵兽出没、秘境开启）
- 国际间的修仙者竞争

## 场景特色
- 写字楼里的修炼室
- 地铁站下的灵脉
- CBD中的法宝拍卖会
- 手机APP交易灵石灵草','["都市", "灵气复苏", "现代", "设定"]',1,'2026-04-13T08:39:52.545801+00:00','2026-04-13T08:39:52.545801+00:00');
INSERT INTO "knowledge_items" VALUES('74e2de2b-0546-4e11-bac0-00ad7ee04937','world','末世修仙设定','末世修仙·世界设定模板','## 核心设定
天地大变后灵气爆发，同时带来妖兽潮、空间裂缝、异族入侵。

## 末世阶段
1. **灾变期**：灵气突然爆发，动植物异变，城市沦陷
2. **求生期**：人类退守安全区，觉醒者成为守护力量
3. **反攻期**：建立修仙体系，夺回失地
4. **新纪元**：修仙文明与科技融合的新世界

## 生存要素
- 安全区/人类基地的等级划分
- 物资（灵石、食物、武器）的稀缺性
- 探险队外出猎杀妖兽获取资源
- 权力斗争：基地内部的派系争斗

## 与传统修仙的区别
- 更强调团队协作而非个人英雄
- 科技武器与法术的结合
- 生存压力带来的道德抉择
- 更快的节奏和更密集的冲突','["末世", "生存", "灵气复苏", "设定"]',1,'2026-04-13T08:39:52.545801+00:00','2026-04-13T08:39:52.545801+00:00');
INSERT INTO "knowledge_items" VALUES('2e865e16-9322-4e90-a179-e0af66beba7f','world','上界设定','仙界/上界·世界设定模板','## 核心设定
飞升后到达的更高层世界，是修仙世界的终极舞台。

## 仙界层级
- **仙人界**：刚飞升者所在，仙人遍地走
- **天宫**：天帝统治的核心区域
- **神界**：更高层的存在，传说中的领域
- **混沌虚空**：诸天万界之间的混沌空间

## 权力结构
- 天帝/仙帝：至高统治者
- 仙尊/仙君：各方霸主
- 仙王/仙将：中坚力量
- 散仙：没有势力依附的自由修士

## 飞升者的困境
- 刚飞升只是最底层，被本土仙人看不起
- 下界的功法和法宝在上界是最低级的
- 需要重新适应更高浓度的灵气
- 从"下界天才"变回"上界菜鸟"

## 叙事价值
重置主角实力感受，重新开始升级爽感','["仙界", "上界", "飞升", "设定"]',1,'2026-04-13T08:39:52.545801+00:00','2026-04-13T08:39:52.545801+00:00');
INSERT INTO "knowledge_items" VALUES('75c072e4-f612-4dd0-adfc-2272e1abc774','world','修仙经济','修仙世界经济体系','## 货币体系
下品灵石 → 中品灵石 → 上品灵石 → 极品灵石 → 仙晶
1中品 = 100下品，1上品 = 100中品

## 交易场所
- **坊市**：宗门/城市设立的固定交易市场
- **地摊区**：散修自发的露天交易
- **拍卖行**：高端物品拍卖，收取佣金
- **黑市**：禁忌物品交易，风险与暴利并存
- **万宝楼**：连锁式的修仙百货

## 经济活动
- 炼丹师/炼器师/阵法师的手艺换灵石
- 猎杀妖兽获取兽丹、皮毛、骨骼
- 灵矿开采和灵田种植
- 护镖/佣兵任务

## 经济冲突素材
- 灵矿争夺引发势力大战
- 物价暴涨（战争/灾变导致）
- 假货（以次充好的丹药/法宝）
- 垄断（某势力垄断关键资源）','["经济", "灵石", "交易", "坊市"]',1,'2026-04-13T08:39:52.545801+00:00','2026-04-13T08:39:52.545801+00:00');
INSERT INTO "knowledge_items" VALUES('6f398b9a-2f8a-4a38-9a09-730ba4946bd3','satisfying','越级战斗','越级战斗·爽点描写技巧','## 核心原理
主角以低境界击败高境界对手，是修仙小说最核心的爽点之一。

## 越级程度参考
- 微越级（1小境界）：常见，不需要特殊解释
- 中越级（1大境界）：需要底牌支撑（法宝/功法/血脉）
- 大越级（2大境界）：需要逆天机缘或特殊战场
- 逆天越级（3+大境界）：极少使用，需要极其合理的解释

## 合理化手段
- 主角修炼的是远古顶级功法，同境界碾压
- 特殊体质加成（战斗力倍增）
- 法宝碾压（以仙器对灵器）
- 战场利用（利用地形、阵法、环境）
- 对手轻敌大意

## 旁观者反应模板
"金丹期……杀了元婴期？！这怎么可能！"
"他到底是什么怪物？同阶无敌也就罢了，竟然还能越级杀人！"
"此子若不除，日后必成大患！"

## 节奏控制
- 不能每次都越级，偶尔遇到同级强敌苦战更有张力
- 越级程度要随剧情递增，不能一开始就越三级','["越级", "战斗", "爽点", "碾压"]',1,'2026-04-13T08:39:52.545801+00:00','2026-04-13T08:39:52.545801+00:00');
INSERT INTO "knowledge_items" VALUES('26de5c43-f190-4b06-9120-2c8b922d7c7a','satisfying','打赌赢宝','打赌赢宝·爽点套路集','## 核心公式
对手出于贪婪/傲慢提出赌约 → 主角淡定接受 → 众人觉得主角必输 → 主角轻松获胜 → 对手想赖账 → 被迫兑现

## 经典赌约类型
### 炼丹对赌
"你若能炼出四品丹药，我把这株万年灵芝送你。若不能，你给我做三年仆从。"

### 战斗对赌
"你若能在我手下撑过十招，我从此绕道走。"
→ 主角一招秒杀。

### 鉴宝对赌
"这石头里绝对没有好东西，我赌一万灵石。"
→ 切出顶级灵晶。

### 修炼对赌
"一年之内你若能突破筑基，我当众向你磕头。"
→ 三个月后主角金丹了。

## 赖账处理
- 有强者在场见证，赖不掉
- 对方家族长辈出面维护信誉
- 主角直接武力讨债','["打赌", "赢宝", "爽点", "打脸"]',1,'2026-04-13T08:39:52.545801+00:00','2026-04-13T08:39:52.545801+00:00');
INSERT INTO "knowledge_items" VALUES('33986f03-8cbb-475e-9a58-8357f4253670','satisfying','底牌揭露','终极底牌揭露·爽点设计','## 核心原理
主角一直隐藏的最强实力在关键时刻展现，造成极致的震撼和爽感。

## 底牌类型
- **隐藏境界**：实际修为比表面高出数个大境界
- **封印血脉**：远古神族血脉觉醒
- **终极法宝**：一直未使用的镇压级法宝
- **禁术/秘技**：有巨大代价的究极招式
- **分身/化身**：真身在别处，此处只是分身

## 揭露时机
- 至亲至爱被威胁时
- 被逼到绝境无路可退时
- 敌人最嚣张最得意的瞬间
- 众人以为主角必死的时候

## 描写节奏
蓄势（压抑到极点）→ 一句话转折 → 底牌展现 → 全场沉默 → 震惊爆发

## 经典转折句
"够了。"（轻描淡写，却让天地变色）
"你以为……这就是我的全部实力吗？"
"既然你想看，那我就让你看看。"（缓缓睁开第三只眼/取下封印）','["底牌", "揭露", "爽点", "震撼"]',1,'2026-04-13T08:39:52.545801+00:00','2026-04-13T08:39:52.545801+00:00');
INSERT INTO "knowledge_items" VALUES('250493d2-35e5-4241-bb8f-23821cffd550','satisfying','护短','护短·情感爽点设计','## 核心原理
主角的亲人/朋友/弟子被欺负，主角挺身而出强势护短。

## 经典场景
### 护妻/护友
"动她一根头发试试。"（全场修士退后三步）

### 护徒
弟子被高阶修士欺负 → 师父降临 → "你觉得你配欺负我的弟子？"

### 护族
家族被灭门 → 主角回归 → 一人一剑灭敌方满门

### 护小弟
手下被人打了 → 主角带人找上门 → "我的人，也是你能动的？"

## 爽感来源
- 强烈的实力对比（碾压保护）
- 情感共鸣（读者代入被保护者视角）
- 反差感（平时温和的主角突然霸气）
- 归属感（跟着主角有安全感）

## 写作要点
- 被欺负的人要让读者有感情
- 施暴者的嚣张要铺垫到位
- 主角出场要有仪式感
- 不要每次都全杀，适当留有余地','["护短", "霸气", "情感", "爽点"]',1,'2026-04-13T08:39:52.545801+00:00','2026-04-13T08:39:52.545801+00:00');
INSERT INTO "knowledge_items" VALUES('22222784-1ece-4eed-ab06-63caf14bb043','satisfying','连升数级','连续突破·爽感叠加技巧','## 核心场景
在关键时刻/获得重大机缘后，主角连续突破多个境界。

## 常见触发
- 吞服极品丹药 + 顶级灵脉闭关
- 秘境中获得远古传承
- 生死大战后的厚积薄发
- 系统奖励连续兑现

## 描写节奏
第一次突破（正常描写）→ 余韵未消 → 灵气继续涌入 → 第二次突破（短促有力）→ 众人震惊 → 天地异象持续 → 第三次突破（极致渲染）→ 全场跪服

## 旁观者反应递进
第一次："他突破了！"
第二次："什么？还在突破？！"
第三次："这……这是疯了吗？一口气三连突破？！"

## 注意事项
- 连续突破不能太频繁，一本书最多2-3次
- 之前必须有足够的积累铺垫（闭关/战斗/机缘）
- 突破后要有展示新实力的场景
- 代价：突破后可能虚弱一段时间','["突破", "连升", "爽点", "境界"]',1,'2026-04-13T08:39:52.545801+00:00','2026-04-13T08:39:52.545801+00:00');
INSERT INTO "knowledge_items" VALUES('7b64ec67-8c61-4f33-b8e8-8ad578db2aa7','foreshadow','功法伏笔','功法/血脉觉醒伏笔模板','## 埋设手法
- 主角修炼某功法时总有一层无法突破
- 功法中有看不懂的古文/符文
- 修炼时体内会出现异常反应（发热、疼痛、异象）
- 别人修炼同一功法没有这种现象

## 回收节奏
- 第一阶段（10%）：修炼异常，以为是副作用
- 第二阶段（30%）：发现功法残缺，需要后续
- 第三阶段（50%）：找到完整版，发现是远古顶级功法
- 第四阶段（70%）：功法与血脉共鸣，觉醒隐藏血脉

## 常见搭配
- 残缺功法 → 实际是大能故意留下考验
- 越修炼越痛苦 → 在重塑体质适配更高层次
- 无法突破的最后一层 → 需要特定血脉/天材地宝催动','["伏笔", "功法", "血脉", "觉醒"]',1,'2026-04-13T08:39:52.545801+00:00','2026-04-13T08:39:52.545801+00:00');
INSERT INTO "knowledge_items" VALUES('51c46258-24bd-4d08-b156-06b0b800b117','foreshadow','世界观伏笔','世界观真相伏笔模板','## 埋设手法
- 历史记载中有被刻意抹去的部分
- 天道/规则中有不合理之处（为什么天道会限制某些修炼）
- 上古强者的遗言中暗含隐晦警告
- 某些禁地存在的原因没人说得清

## 大伏笔示例
- 整个修仙世界是某位大能的洞天
- 天道实际是上古强者设立的枷锁
- 所谓的"飞升"其实是另一种形式的囚禁
- 修仙世界的历史被人为篡改过

## 回收方式
- 通过古籍/壁画逐步拼凑真相
- 到达一定境界后"看到"被隐藏的规则
- 与上古残魂交流得知真实历史
- 亲眼见证"飞升"的真相

## 写作注意
- 这种大伏笔要在开书时就规划好
- 中途的线索要足够但不过分明显
- 真相揭露时要让读者感到震撼但又合理','["伏笔", "世界观", "真相", "大伏笔"]',1,'2026-04-13T08:39:52.545801+00:00','2026-04-13T08:39:52.545801+00:00');
INSERT INTO "knowledge_items" VALUES('09770e33-e6dc-439d-94e9-65d0d2a32882','foreshadow','情感伏笔','感情线伏笔模板','## 埋设手法
- 初遇时的特殊互动（救命之恩/信物交换/一句承诺）
- 不经意间的对视或身体接触
- 第三方角色的无心之言暗示两人关系
- 共同经历危险后的微妙变化

## 回收节奏
- 相遇（种子）：看似普通的第一次见面
- 相知（发芽）：在冒险/危机中加深了解
- 误会（考验）：因身份/立场产生隔阂
- 真心（开花）：危急时刻真情流露
- 相守（结果）：克服障碍走到一起

## 经典伏笔设计
- 送的"普通"玉佩其实是定情信物的一半
- 偶然说的一句话后来成为关键台词
- 第一次见面时对方就注意到了主角
- 看似巧合的多次相遇实际有人暗中安排','["伏笔", "感情", "情感线", "铺垫"]',1,'2026-04-13T08:39:52.545801+00:00','2026-04-13T08:39:52.545801+00:00');
INSERT INTO "knowledge_items" VALUES('35bba7bc-b41b-4c7d-9b91-7165770e2005','foreshadow','死亡伏笔','重要角色死亡伏笔模板','## 埋设手法（让读者隐隐不安）
- 角色突然交代后事/回忆往昔
- 说出"等这件事结束后我就……"这类flag
- 对主角说出意味深长的告别式台词
- 完成了自己最大的心愿

## 死亡类型
### 壮烈牺牲型
- 为保护主角/大局慷慨赴死
- 死前的最后一击要极其震撼
- 给主角留下信物/遗言/力量

### 意外死亡型
- 在读者放松警惕时突然发生
- 没有英雄式的告别，更加真实和痛苦
- 制造极大的情感冲击

### 陨落后回响
- 其他角色的悲痛反应
- 主角因此获得更强的动力/决心
- 死者的遗志成为后续剧情推动力

## 写作注意
- 要死的角色必须让读者有感情（至少铺垫10章）
- 死亡要有意义，不能白死
- 不要频繁杀角色，每次都要有足够冲击力','["伏笔", "死亡", "牺牲", "情感"]',1,'2026-04-13T08:39:52.545801+00:00','2026-04-13T08:39:52.545801+00:00');
INSERT INTO "knowledge_items" VALUES('e7a41e0e-cb7c-4878-bd15-54f447a6ba3c','chapter_template','回忆章','回忆/倒叙章·写作模板','## 适用场景
- 角色死亡后回顾生平
- 主角在关键突破时回忆过往
- 揭露某角色不为人知的过去
- 解释当前事件的历史原因

## 结构
1. **触发点**（200字）：当前场景中的某个细节触发回忆
2. **回忆正文**（1500字）：过去的完整场景
3. **回忆结束**（200字）：从回忆中回到现实
4. **情感升华**（300字）：因回忆而产生的觉悟/决心

## 切入切出技巧
切入："看着手中的玉佩，记忆如潮水般涌来——那是十年前的冬天……"
切出："玉佩上的温度渐渐冷却，他回过神来。十年了……"

## 注意事项
- 回忆不宜过长，控制在全章的40-60%
- 回忆内容要与当前剧情有因果关系
- 不要在紧张剧情中间插入长回忆
- 回忆中要有新信息，不能只是重复已知内容','["回忆", "倒叙", "模板", "情感"]',1,'2026-04-13T08:39:52.545801+00:00','2026-04-13T08:39:52.545801+00:00');
INSERT INTO "knowledge_items" VALUES('51bc4e42-944b-4f44-a801-67bdb0def02a','chapter_template','密谋章','阴谋密谋章·写作模板','## 适用场景
- 反派势力密谋对付主角
- 各方势力暗中博弈
- 战争前夕的情报战
- 揭露真相前的拼图

## 结构
1. **多视角切换**（交替推进）：
   - A线：主角方的准备和判断
   - B线：敌方的密谋和布局
   - C线（可选）：第三方的暗中观察
2. **信息不对称**：读者知道的比主角多
3. **紧张递进**：双方距离碰撞越来越近
4. **章末悬念**：两条线即将交汇的瞬间

## 写作技巧
- 不要一次性揭露全部阴谋，层层剥开
- 敌方的计划要有智商，不能太蠢
- 给主角留一两个"没想到"的变数
- 用短段落和短句加快紧迫感

## 节奏参考
密谋铺垫(3-4章) → 计划启动(1章) → 正面碰撞(2-3章) → 反转收束(1章)','["阴谋", "密谋", "多视角", "模板"]',1,'2026-04-13T08:39:52.545801+00:00','2026-04-13T08:39:52.545801+00:00');
INSERT INTO "knowledge_items" VALUES('13353820-27ec-4600-a734-e738aa144839','chapter_template','感情章','感情发展章·写作模板','## 适用场景
- 主角与女主/重要角色的关系推进
- 表白/误会/和好等情感节点
- 用于紧张剧情间的调节

## 结构
1. **氛围营造**（300字）：场景、天气、环境配合情感基调
2. **互动推进**（800字）：通过对话和行动展示关系变化
3. **情感转折**（400字）：一个关键事件/话语打破僵局
4. **心理刻画**（300字）：双方内心的波动
5. **余韵收束**（200字）：留下余味，不要太满

## 修仙感情线的特殊性
- 寿命差距带来的矛盾（凡人爱上修士）
- 道侣制度的仪式感
- 双修功法的暧昧空间
- 闭关数十年的离别和等待

## 对话技巧
- 不要直接说"我喜欢你"，用行动和隐喻
- "你身上有伤。" "不碍事。" "……你骗人。"
- 言外之意比言内之意更重要
- 修仙者的含蓄：以赠法宝/丹药代替表白','["感情", "恋爱", "互动", "模板"]',1,'2026-04-13T08:39:52.545801+00:00','2026-04-13T08:39:52.545801+00:00');
INSERT INTO "knowledge_items" VALUES('ecc83844-bef7-4baa-9d10-2aeba881607c','chapter_template','终章模板','全书终章·写作模板','## 核心任务
- 收束所有主线和重要支线
- 给主角一个圆满（或开放）的结局
- 给读者情感上的满足和释放

## 结构
1. **最终大战后**（500字）：战后余波，处理最终BOSS的结局
2. **故人重聚**（500字）：与重要角色的重逢/告别
3. **伏笔收尾**（300字）：回收最后的伏笔
4. **时间跳跃**（400字）：数年/数十年后的世界
5. **最终画面**（300字）：主角最后的身影/一句话

## 结尾类型
### 功成身退型
"他看着脚下的三千世界，微微一笑，身影渐渐消散在天际。"

### 新的征程型
"仙界之上，还有更广阔的天地在等着他。"

### 归于平凡型
"放下剑，回到那个小村庄，推开那扇记忆中的门。"

### 开放式结尾
"天边又亮起了那道光……和千年前一模一样。"

## 注意事项
- 不要赶结尾，留足够篇幅给情感收束
- 呼应开篇第一章的某个细节（首尾呼应）
- 配角也要有交代，不能突然消失
- 给读者留下回味的空间','["终章", "结局", "收束", "模板"]',1,'2026-04-13T08:39:52.545801+00:00','2026-04-13T08:39:52.545801+00:00');
INSERT INTO "knowledge_items" VALUES('ab2e73d5-8a5c-4e03-9330-a3435cd2b931','plot','夺舍反杀','夺舍/反夺舍·经典模板','## 核心结构
1. **觊觎肉身**：老怪物/邪修看上主角的特殊体质/根基
2. **夺舍启动**：趁主角虚弱/闭关时发动夺舍秘术
3. **意识对抗**：主角灵魂在识海中与夺舍者殊死搏斗
4. **绝境觉醒**：主角触发隐藏血脉/系统护体/意志觉醒
5. **反噬吞并**：反过来吞噬夺舍者的记忆和部分修为

## 变体
- **被夺舍后的复仇**：身体被占→残魂在法宝中苟延→夺回身体
- **主动吸收**：不杀夺舍者残魂，将其封印吸收知识
- **夺舍留情**：夺舍者其实是主角的前世/至亲

## 叙事价值
- 提供大量修为/记忆的快速获取（合理加速成长）
- 揭露上古秘辛
- 制造身份认同危机："被夺舍后的我还是我吗？"

## 写作注意
- 夺舍过程必须有代价，不能白嫖
- 识海大战要有画面感，不能只写"意志碰撞"
- 吞噬记忆后不能全知全能，要有信息缺失','["夺舍", "反杀", "识海", "灵魂"]',1,'2026-04-13T09:34:28.840326+00:00','2026-04-13T09:34:28.840326+00:00');
INSERT INTO "knowledge_items" VALUES('0585532b-bc97-439b-bc84-6000fd2b770c','plot','宗门覆灭重建','宗门覆灭与重建·经典模板','## 核心结构
### 覆灭篇
1. **太平假象**：宗门日常运转，主角是普通弟子
2. **强敌降临**：远超宗门实力的势力碾压式进攻
3. **浴血死守**：长老舍命抵挡，弟子四散逃亡
4. **灰烬之中**：主角带着宗门秘传/信物逃出

### 重建篇
1. **流亡苦修**：主角在外漂泊修炼，积累实力
2. **寻找旧人**：逐一找回幸存的师兄弟
3. **打回老家**：实力足够后重返故地
4. **宗门新生**：在旧址重建，吸引新弟子

## 情感核心
- 废墟上的誓言："总有一天，我会重建这里"
- 重遇旧人时的百感交集
- 新弟子问"这里以前什么样"时的回忆
- 最终站在重建的宗门门口回想当年

## 与复仇线的结合
覆灭宗门者 = 主线大反派，重建与复仇交织推进','["宗门", "覆灭", "重建", "复仇"]',1,'2026-04-13T09:34:28.840326+00:00','2026-04-13T09:34:28.840326+00:00');
INSERT INTO "knowledge_items" VALUES('22c72d4b-516d-4c80-b356-06964e2d36d5','plot','走火入魔','走火入魔/暴走·危机模板','## 触发条件
- 修炼禁忌功法反噬
- 突破瓶颈时心魔侵蚀
- 亲人/挚友死亡导致情绪崩溃
- 被人暗中下毒/种心魔

## 核心结构
1. **前兆**：修炼中灵气暴走/性情变化/经脉异常
2. **爆发**：失控暴走，攻击周围一切（包括同伴）
3. **拉扯**：同伴试图唤醒/压制，主角内心的理智与魔性斗争
4. **关键一击**：某个深刻的记忆/羁绊成为转折点
5. **平息代价**：恢复理智但付出代价（境界跌落/寿元损耗/受伤）

## 叙事价值
- 展示主角脆弱的一面（不是一路无敌）
- 加深主角与同伴的羁绊
- 引出心魔/禁忌功法的后续剧情线
- 制造"力量的代价"主题

## 后续影响
- 对暴走时伤害同伴的愧疚
- 对自身力量的恐惧和反思
- 寻找根治心魔的方法（新剧情线）','["走火入魔", "暴走", "心魔", "危机"]',1,'2026-04-13T09:34:28.840326+00:00','2026-04-13T09:34:28.840326+00:00');
INSERT INTO "knowledge_items" VALUES('5c147c80-677d-4643-b75a-adc243deb43e','plot','万族大会','万族大会/天才排位·经典模板','## 核心结构
1. **大会召集**：各族/各界天才齐聚，争夺排名和资源
2. **资格选拔**：先淘汰弱者，主角低调晋级
3. **群雄亮相**：展示各路天骄的实力和特色
4. **层层晋级**：小组赛→淘汰赛→半决赛→决赛
5. **黑马崛起**：主角从无人看好到一路碾压
6. **最终对决**：与最强天骄的巅峰之战

## 与宗门大比的区别
- 规模更大：跨宗门/跨区域/跨种族
- 对手更强：每个对手都有独特绝技
- 影响更深：排名决定资源分配/婚约/领地

## 赛制设计
- 积分制（允许战术选择对手）
- 擂台淘汰制（连胜获额外奖励）
- 团队战+个人战结合
- 特殊关卡（幻阵考验/炼丹比拼/生存挑战）

## 经典爽点
- "此人是谁？从未听说过！" → 连胜后全场打听
- 各大势力抢着招揽
- 击败上届冠军
- 赛后收获一堆崇拜者/追随者','["大会", "天才", "排名", "比试"]',1,'2026-04-13T09:34:28.840326+00:00','2026-04-13T09:34:28.840326+00:00');
INSERT INTO "knowledge_items" VALUES('9c9001b6-3a29-47cd-a0ff-8a59b9ccf239','plot','禁忌之恋','禁忌之恋·感情冲突模板','## 常见设定
- 人族与妖族/魔族的跨族恋情
- 正道与魔道弟子相爱
- 师徒恋（辈分禁忌）
- 曾经的仇敌后人相爱

## 核心结构
1. **意外相遇**：在特殊环境下相识（秘境/战场/流亡）
2. **身份隐瞒**：隐藏真实身份逐渐产生感情
3. **真相揭露**：身份暴露，双方阵营施压
4. **抉择考验**：在爱情与阵营之间做出选择
5. **共同抗争**：联手对抗不公的规则/偏见

## 冲突设计
- 两人背后的势力是死敌
- "杀了他/她，否则逐出师门"
- 因为爱情被双方阵营追杀
- 孩子继承双方血脉引发更大冲突

## 写作要点
- 感情发展要有足够铺垫，不能因为"禁忌"就省略过程
- 两人要有除了爱情之外的mutual respect
- 结局可以HE也可以BE，但过程要动人
- 禁忌的根源要有合理的历史/文化解释','["感情", "禁忌", "跨族", "冲突"]',1,'2026-04-13T09:34:28.840326+00:00','2026-04-13T09:34:28.840326+00:00');
INSERT INTO "knowledge_items" VALUES('a4e1dfb4-d089-42d5-8637-acc677d63cd4','plot','时间回溯','时间回溯/时空乱流·经典模板','## 核心结构
1. **时间异变**：因秘境/法宝/大能出手导致时间回溯
2. **过去重历**：主角回到过去的某个关键节点
3. **蝴蝶效应**：试图改变过去引发连锁反应
4. **时间悖论**：改变过去后当下也发生了变化
5. **回归当下**：带着过去获得的信息/力量回到现在

## 与重生流的区别
- 时间回溯是短暂的（几天到几个月），重生是永久的
- 时间回溯通常是中后期剧情，重生是开局设定
- 时间回溯可以多次使用（有代价），重生只有一次

## 叙事用途
- 揭露历史真相（亲眼见证上古大战）
- 获得失传的功法/信息
- 改变某个已经发生的悲剧
- 理解某个角色当初为什么那样做

## 代价与限制
- 每次回溯消耗大量寿元
- 不能改变"天道注定"的事件
- 在过去待太久会被时间法则排斥
- 可能引起更大的灾难（蝴蝶效应）','["时间", "回溯", "时空", "秘境"]',1,'2026-04-13T09:34:28.840326+00:00','2026-04-13T09:34:28.840326+00:00');
INSERT INTO "knowledge_items" VALUES('138140d4-996e-4fe6-983b-9f792bca35e5','character','镜像对照角色','镜像对照·同源异路角色模板','## 核心设计
两个起点相似但走上完全不同道路的角色，形成鲜明对比。

## 经典搭配
- 同门师兄弟：一人走正道一人入魔道
- 同族双子：一人被家族培养一人被抛弃
- 同时代天才：一人选择守护一人选择毁灭
- 穿越者 vs 本土天才：现代思维 vs 传统修仙观

## 叙事价值
- 通过对比展现"选择"的力量
- 反派不再是脸谱化的恶人，而是"另一个可能的自己"
- 最终对决时两人的对话升华主题
- "如果当初我走了他的路，会不会也变成这样？"

## 关键设计
- 两人必须有足够的相似点（出身/能力/经历）
- 分道扬镳的节点要清晰且合理
- 两人要有多次交手和对话，每次都深化主题
- 最终结局要有意义：感化/惺惺相惜/不得不战','["对照", "镜像", "主题", "深度"]',1,'2026-04-13T09:34:28.840326+00:00','2026-04-13T09:34:28.840326+00:00');
INSERT INTO "knowledge_items" VALUES('ba8e4ab2-1b54-4ec5-b9e1-e35fc95b3e81','character','帝王角色','帝王/宗主型角色模板','## 核心特征
- 统治一方的领袖人物，既是盟友也可能是敌人
- 表面威严冷酷，内心有复杂的考量和苦衷
- 做决策时权衡利弊，不会因私情影响大局

## 类型划分
### 明君型
- 爱民如子，为大局做出艰难决策
- 对主角暗中扶持但不能公开偏袒
- "朕也想帮你，但朕是皇帝，不是你朋友"

### 枭雄型
- 不择手段但有大格局
- 用人不疑，赏罚分明
- 与主角是博弈关系：利用但不完全对立

### 昏庸型（工具角色）
- 被奸臣蒙蔽/沉迷修炼不问世事
- 制造"清君侧"或"推翻暴政"的剧情动力

## 与主角的互动模式
- 试探期：暗中观察主角，评估威胁还是助力
- 合作期：借助主角力量解决危机
- 冲突期：主角成长到威胁其地位时','["帝王", "宗主", "领袖", "政治"]',1,'2026-04-13T09:34:28.840326+00:00','2026-04-13T09:34:28.840326+00:00');
INSERT INTO "knowledge_items" VALUES('22243981-d10a-43e4-804e-15597fc24d28','character','隐世强者','隐世强者/扫地僧型角色模板','## 核心设计
身份低微但实力恐怖的隐藏角色，关键时刻一鸣惊人。

## 经典形象
- 宗门扫地老头（实际是太上长老/创派祖师）
- 街边算命先生（实则天道之下第一人）
- 茶铺老板（退隐的绝世高手）
- 乞丐（装疯卖傻的上古遗老）

## 叙事功能
- **救场**：关键时刻出手救主角
- **点拨**：一句话让主角茅塞顿开
- **震慑**：吓退追杀主角的强敌
- **传承**：将毕生所学传给主角

## 出场节奏
- 第一次：不经意出现，读者和主角都没察觉
- 第二次：展露一丝不凡，主角开始留意
- 第三次：身份揭晓，全场震惊

## 写作要点
- 身份揭露前要有足够的铺垫（回头看合理）
- 不能频繁出场救场，否则主角失去独立性
- 隐世的原因要说得通（伤势/誓言/考验后人）
- 退场也要有交代（不能用完就消失）','["隐世", "强者", "扫地僧", "神秘"]',1,'2026-04-13T09:34:28.840326+00:00','2026-04-13T09:34:28.840326+00:00');
INSERT INTO "knowledge_items" VALUES('c238232e-f3e3-4ee3-b354-934489904d2b','character','叛变配角','叛变/背叛型配角模板','## 核心设计
前期深得信任的伙伴，在关键时刻背叛主角。

## 背叛类型
### 被迫型
- 至亲被敌方控制，不得不背叛
- 内心痛苦但无法告诉任何人
- 最终可能为主角挡下致命一击赎罪

### 野心型
- 一直隐藏野心，表面忠诚
- 在得到足够好处后倒戈
- 是真正让读者恨得牙痒痒的角色

### 理念分歧型
- 与主角理念产生根本分歧
- 认为自己才是对的
- 不完全是坏人，但站在了对立面

## 铺垫技巧
- 早期偶尔展现与主角不同的价值观
- 在某些选择上犹豫/沉默
- 与敌方的某些互动被轻描淡写带过
- 对主角"太好"反而是铺垫（过度补偿心理）

## 写作注意
- 背叛前必须让读者真的喜欢/信任这个角色
- 背叛的理由必须充分，不能为反转而反转
- 背叛后给主角留下深刻的心理创伤','["背叛", "叛变", "反转", "配角"]',1,'2026-04-13T09:34:28.840326+00:00','2026-04-13T09:34:28.840326+00:00');
INSERT INTO "knowledge_items" VALUES('46d6f77d-0c85-4914-a58e-379f397d24f3','character','天道化身','天道/规则化身型角色模板','## 核心设计
天道规则的具象化存在，超脱善恶的特殊角色。

## 类型
### 冷漠天道
- 只执行规则，不带任何感情
- 阻止主角超越天道限制
- "你太强了，天道容不下你"

### 觉醒天道
- 在与主角互动中逐渐产生自我意识
- 开始质疑自己执行的规则是否合理
- 可能成为主角的盟友或最终对手

### 伪天道
- 自称天道实际是上古强者冒充
- 利用"天道"身份操控世界
- 被揭穿后成为最终BOSS

## 叙事价值
- 作为世界观最终谜团的关键
- 提供"人定胜天"的主题升华
- 制造最高级别的对手（超越修为的存在）

## 与主角的互动
- "你很特别，但规则就是规则"
- 每次渡劫时天道加码考验
- 最终主角选择破碎天道/重立天道/成为新天道','["天道", "规则", "化身", "终极"]',1,'2026-04-13T09:34:28.840326+00:00','2026-04-13T09:34:28.840326+00:00');
INSERT INTO "knowledge_items" VALUES('41f8e37d-1d85-4c35-bec9-dc74860c6745','world','妖兽体系','妖兽等级与进化体系','## 妖兽等级
一阶妖兽（对应练气）→ 二阶（筑基）→ 三阶（金丹）→ 四阶（元婴）
→ 五阶妖王（化神）→ 六阶妖皇（合体）→ 七阶妖帝（大乘）→ 远古神兽

## 进化方式
- **自然进化**：吸收天地灵气缓慢成长
- **吞噬进化**：吞噬同类/高阶妖丹快速提升
- **返祖进化**：血脉觉醒，回归远古祖先形态
- **渡劫化形**：达到一定等级后渡劫化为人形

## 经典妖兽分类
- **天空系**：金翅大鹏、凤凰、雷鹰、九头鸟
- **水域系**：蛟龙、玄龟、巨鲸、鲲鹏
- **大地系**：麒麟、白虎、石灵、万年蟒蛇
- **灵类系**：灵狐、仙鹤、月兔、灵猿

## 妖兽材料价值
- 妖丹：炼丹核心材料
- 妖血：绘制阵法/淬炼法宝
- 骨骼/爪牙：炼器上品材料
- 皮毛：制作防御法衣
- 内丹：修炼辅助（吞噬有风险）','["妖兽", "等级", "进化", "材料"]',1,'2026-04-13T09:34:28.840326+00:00','2026-04-13T09:34:28.840326+00:00');
INSERT INTO "knowledge_items" VALUES('85a052f4-6aa1-477a-98c2-d7ded2b4885d','world','阵法详解','阵法体系详解','## 阵法分类

### 按用途
- **聚灵阵**：汇聚灵气辅助修炼
- **护山大阵**：宗门/城池防御核心
- **杀阵**：困杀入侵者（万剑阵、五行灭杀阵）
- **困阵**：困住对手无法脱身
- **幻阵**：制造幻象迷惑心智
- **传送阵**：空间转移（城市间/跨区域）
- **封印阵**：封印妖兽/强者/秘境入口

### 按品质
凡阵（练气可布）→ 灵阵（金丹可布）→ 宝阵（元婴可布）→ 圣阵（化神可布）→ 仙阵（传说级）

## 阵法师设定
- 布阵需要阵旗、阵盘、阵眼石等材料
- 高级阵法师极其稀缺，地位不低于炼丹师
- 能破阵者同样珍贵
- 阵法的核心在阵眼，破了阵眼阵法即溃

## 战斗中的阵法运用
- 以弱胜强的关键（提前布阵伏击强敌）
- 团战核心（多人联合阵法增幅战力）
- 攻城战的决定性因素','["阵法", "布阵", "破阵", "体系"]',1,'2026-04-13T09:34:28.840326+00:00','2026-04-13T09:34:28.840326+00:00');
INSERT INTO "knowledge_items" VALUES('e56e5d04-384f-4583-88a4-26fcbab6e340','world','炼丹详解','炼丹术详解·流程与设定','## 炼丹流程
1. **选材**：按丹方准备灵草/矿物/妖丹等材料
2. **预处理**：研磨、炮制、萃取精华
3. **起炉**：点燃丹火（地火/兽火/灵火/天火）
4. **炼化**：按顺序投入材料，控制火候
5. **凝丹**：灵力引导药液凝结成丹
6. **成丹**：丹成瞬间可能引发丹雷/异香

## 丹火等级
凡火 → 地火 → 兽火 → 灵火 → 天火（雷火/凤火/三昧真火）→ 混沌之火

## 丹药品质
废丹（失败品）→ 下品 → 中品 → 上品 → 极品 → 带丹纹（每多一道纹品质翻倍）

## 炼丹师等级
一品（练气级丹药）→ 二品（筑基级）→ ... → 九品（渡劫级）

## 常见丹药速查
| 用途 | 低阶 | 中阶 | 高阶 |
|------|------|------|------|
| 修炼 | 聚灵丹 | 培元丹 | 化神丹 |
| 疗伤 | 回春丹 | 续命丹 | 再生丹 |
| 突破 | 筑基丹 | 凝丹散 | 破境丹 |
| 解毒 | 解毒丹 | 万毒丹 | 至圣解毒丹 |

## 炼丹爽点
- 炼废的材料别人扔了主角捡起来二次炼制
- 一炉出多丹（远超正常数量）
- 丹成引天劫（品质逆天的标志）','["炼丹", "丹药", "丹火", "流程"]',1,'2026-04-13T09:34:28.840326+00:00','2026-04-13T09:34:28.840326+00:00');
INSERT INTO "knowledge_items" VALUES('aa255a36-36d4-4bbf-aaa2-35bf03384ce0','world','天道规则','天道法则与因果体系','## 天道核心规则
- **因果法则**：有因必有果，强者杀戮过多会遭天道反噬
- **天道制衡**：不允许一人实力超越天道容忍的极限
- **功德与业力**：善行积功德，恶行增业力，影响渡劫难度
- **天劫法则**：境界越高天劫越重，天妒之资天劫更甚

## 天道禁忌
- 逆天改命（改变注定之人的命运）
- 窥探天机（推算过多会折损寿元）
- 弑杀同道（同门相残天道不容）
- 以大欺小（高境界对低境界出手会遭天谴）

## 气运系统
- 每个人生而有气运，可增可减
- 气运旺者机缘多、渡劫顺
- 抢夺他人气运是大忌（但有人铤而走险）
- 主角通常是"气运之子"

## 叙事运用
- 天道是最高层面的冲突制造者
- "天道不公"是很多反派的动机
- 主角挑战天道是终极升华
- 可以设计"天道有缺"或"天道被操控"作为大伏笔','["天道", "因果", "气运", "法则"]',1,'2026-04-13T09:34:28.840326+00:00','2026-04-13T09:34:28.840326+00:00');
INSERT INTO "knowledge_items" VALUES('79c68a0d-860b-4ca4-baad-d2e101bc49f5','world','古族血脉','远古种族与血脉体系','## 远古种族
- **龙族**：最强战力种族，血脉等级森严
- **凤族**：涅盘重生，掌控天火
- **麒麟族**：祥瑞之兽，防御无双
- **人族**：数量最多，潜力最大，变数最多
- **妖族**：万妖林立，以血脉定尊卑
- **魔族**：域外天魔，与修仙界对立
- **灵族**：天生通灵，感知力极强

## 血脉等级
普通血脉 → 变异血脉 → 远古血脉 → 神兽血脉 → 始祖血脉

## 血脉觉醒方式
- 生死之际：濒死时血脉自动激活护主
- 天材地宝：特定的果实/泉水催化血脉
- 秘境传承：远古祖先留下的血脉洗礼
- 境界突破：到达特定境界自然觉醒
- 情感激荡：极度愤怒/悲伤时爆发

## 混血设定
- 混血儿通常被双方种族排斥
- 但混血可能激活两种血脉的融合力量
- "不纯"的血脉反而可能产生变异进化
- 经典冲突：在两个种族之间选择立场','["血脉", "种族", "远古", "觉醒"]',1,'2026-04-13T09:34:28.840326+00:00','2026-04-13T09:34:28.840326+00:00');
INSERT INTO "knowledge_items" VALUES('5ffb72c6-4006-4850-b7c5-7dfb2f6b0968','world','灵植体系','灵植体系与灵田设定','## 灵植分级
凡草（百年以下）→ 灵草（百年-千年）→ 宝草（千年-万年）→ 圣药（万年以上）→ 仙草（传说级）

## 灵植生长条件
- 灵气浓度：灵脉之上生长最快
- 特殊环境：火山口（火属性灵植）、深海（水属性）、雷区（雷属性）
- 时间：年份越久药性越强
- 伴生：某些灵植需要特定妖兽/矿石伴生

## 灵田经营
- 开辟灵田需要灵脉支撑
- 聚灵阵加速灵植生长
- 药园管理是宗门重要收入
- 珍稀种子的价值不亚于成品丹药

## 经典灵植
- 九叶灵芝（修炼圣药）
- 火灵果（火属性修士必备）
- 万年冰莲（疗伤圣药）
- 龙血草（淬炼体质）
- 混沌青莲（传说级，可助突破大境界）

## 叙事价值
- 争夺珍稀灵植是冲突来源
- 灵田经营是建设流的核心玩法
- "主角的后花园里种着逆天灵植"是长线铺垫','["灵植", "灵草", "灵田", "药材"]',1,'2026-04-13T09:34:28.840326+00:00','2026-04-13T09:34:28.840326+00:00');
INSERT INTO "knowledge_items" VALUES('c968662d-a1d4-4854-91ec-bbad4d700d40','satisfying','收服降服','收服/降服·爽点设计','## 核心公式
高傲的强者/妖兽拒绝臣服 → 主角展示实力/人格魅力 → 对方从不屑到震惊到心悦诚服

## 收服类型
### 以力服人
- 将对方打到心服口服
- "你很强，但还不够"
- 对方从对手变为小弟

### 以德服人
- 在对方危难时出手相救
- 不计前嫌的宽容
- "你可以不认我为主，但我不会见死不救"

### 以智服人
- 看穿对方的困境并提出解决方案
- 用战略眼光赢得对方认可
- "跟着我，比你自己混强百倍"

### 契约收服（灵兽）
- 以血为契，灵魂绑定
- 共享修为提升
- 从抗拒到依赖到并肩作战

## 爽感来源
- 曾经不可一世的强者对主角俯首称臣
- 旁人："他居然跟了这个小子？！"
- 收服越多，主角团越壮大的成就感','["收服", "降服", "小弟", "爽点"]',1,'2026-04-13T09:34:28.840326+00:00','2026-04-13T09:34:28.840326+00:00');
INSERT INTO "knowledge_items" VALUES('aceba402-aee0-4b35-ad04-b79d25f924da','satisfying','以一敌百','以一敌百·名场面设计','## 核心场景
主角独自面对大量敌人（军队/围攻/宗门围剿），以一己之力碾压。

## 经典场景
### 守关型
- 独守城门/山口，万军不敢前进
- "有我在，你们一个都过不去"

### 闯阵型
- 单枪匹马闯入敌方大本营
- 一路碾压，无人能挡
- 直取敌方首领

### 屠杀型（慎用）
- 亲人被害后的暴怒屠杀
- 气势压制：低阶修士直接跪下
- 高阶修士拼命也挡不住

## 描写技巧
- 先写对方的人数和声势（反衬）
- 主角出手的第一招要极致震撼
- 用旁观者视角放大冲击力
- 战后的寂静比战斗本身更有力

## 经典描写
"他站在万军之前，身后是他要守护的一切。
第一剑，斩落敌方先锋大将。
第二剑，剑气横扫三千铁骑。
第三剑……没有人敢等第三剑。"

## 使用频率
全书不超过2-3次，太多会审美疲劳','["以一敌百", "名场面", "碾压", "震撼"]',1,'2026-04-13T09:34:28.840326+00:00','2026-04-13T09:34:28.840326+00:00');
INSERT INTO "knowledge_items" VALUES('eb272009-8819-4cf2-95f5-2e5b0ad077b9','satisfying','认可与尊重','获得认可·情感爽点设计','## 核心原理
主角长期不被认可，最终获得曾经看不起自己的人的尊重。

## 层次递进
1. **被看不起**：所有人都认为主角是废物/不可能成功
2. **独自坚持**：在嘲笑中默默努力
3. **初露锋芒**：开始展现实力，质疑声减少
4. **不得不服**：成就到了不服不行的程度
5. **众人认可**：曾经的质疑者心悦诚服

## 经典场景
### 父辈认可
- "我曾经以为你是家族的耻辱……我错了"
- 严厉父亲第一次露出骄傲的眼神

### 同辈认可
- 曾经嘲笑的同门："他才是真正的天才"
- 曾经的对手主动请教

### 强者认可
- 大能："此子前途不可限量"
- 获得宗门最高荣誉/称号

### 众人认可
- 万人面前被称颂
- 名字传遍修仙界

## 爽感来源
- 不是暴力碾压，而是尊严的收回
- 那些曾经的冷眼变成了仰望
- 读者长期代入后的情感释放','["认可", "尊重", "成长", "情感爽点"]',1,'2026-04-13T09:34:28.840326+00:00','2026-04-13T09:34:28.840326+00:00');
INSERT INTO "knowledge_items" VALUES('31272a21-7771-4700-917c-3e5f520d939b','satisfying','装逼反转','装逼-否定-反转·经典三段式','## 核心公式
角色A装逼说大话 → 被所有人否定嘲笑 → A用实力证明自己说的全是事实

## 适用场景
### 主角型装逼
主角：""这丹药有瑕疵。"
炼丹大师（怒）："你一个练气期也敢质疑我？！"
→ 主角随手改良，品质翻倍 → 大师老脸通红

### 被动型装逼
别人："你能治好这绝症？别吹了。"
主角默默出手 → 药到病除 → 全场安静

### 反向装逼
主角故意示弱："我不太行，要不你来？"
→ 对方得意上场 → 惨败
→ 主角淡定上场 → 轻松完成 → "还行吧。"

## 升级版：连环装逼
第一层：击败普通对手 → "就这？"
第二层：强者出手 → 依然碾压 → "还有谁？"
第三层：BOSS级别 → 苦战后胜出 → 不说话，转身离去
（最后一层要稍有挑战性，不能全程碾压）

## 节奏要点
- 铺垫越多，反转越爽
- 否定的人越权威，打脸越痛快
- 主角要淡定，越淡定越帅','["装逼", "反转", "打脸", "爽点"]',1,'2026-04-13T09:34:28.840326+00:00','2026-04-13T09:34:28.840326+00:00');
INSERT INTO "knowledge_items" VALUES('ebf81e29-9f39-415d-bbd2-d4e49ef958a0','satisfying','传承觉醒','获得传承/血脉觉醒·爽点模板','## 核心场景
主角在秘境/危急时刻获得远古大能的传承或觉醒隐藏血脉。

## 传承类型
- **功法传承**：获得远古顶级功法，修炼速度质变
- **记忆传承**：继承大能一生修炼感悟
- **力量传承**：直接获得一部分力量（有副作用）
- **器灵传承**：法宝器灵认主，传授使用方法
- **血脉觉醒**：激活沉睡的远古血脉

## 描写节奏
蓄势（进入秘境/触发机关）→ 考验（大能残魂的测试）→ 认可（"你通过了"）→ 传承灌注（痛苦蜕变）→ 觉醒（实力暴涨）→ 展示新力量

## 描写要点
- 传承过程要有仪式感和画面感
- 接受传承时的痛苦蜕变要写到位
- 传承后第一次使用新能力要震撼
- 传承者的残魂可以有一段感人对话

## 注意事项
- 传承不能太频繁，每获得一次都要有足够间隔
- 传承要有筛选条件（不是谁都能得到）
- 传承的力量要逐步解锁，不能一次性全给','["传承", "觉醒", "血脉", "爽点"]',1,'2026-04-13T09:34:28.840326+00:00','2026-04-13T09:34:28.840326+00:00');
INSERT INTO "knowledge_items" VALUES('a7c32c51-7841-4f19-8ca7-4d9422cd2f98','foreshadow','梦境伏笔','梦境/异象伏笔模板','## 埋设手法
- 主角反复做同一个模糊的梦
- 梦中出现未见过的人/地点/场景
- 每次梦境比上一次清晰一点
- 梦中的某些元素后来在现实中出现

## 梦境类型
### 预知型
- 梦到未来将要发生的场景（但视角模糊）
- 实际发生时主角有似曾相识感

### 前世型
- 梦到前世的片段记忆
- 梦中的技能在现实中无意识使出

### 感应型
- 梦到远方至亲的危险
- 血脉共鸣引发的跨空间感知

### 天道启示型
- 天道通过梦境传达警告/指引
- 梦中出现修炼感悟（醒来后突破）

## 回收方式
- 到达某地时："这个地方……我在梦里见过！"
- 遇到某人时："你……你是梦里的那个人？"
- 关键抉择时：梦境中的场景指引了正确选择

## 回收节奏
每隔20-30章做一次梦 → 第一次验证（50%进度）→ 全部揭示（70-80%进度）','["梦境", "伏笔", "预知", "前世"]',1,'2026-04-13T09:34:28.840326+00:00','2026-04-13T09:34:28.840326+00:00');
INSERT INTO "knowledge_items" VALUES('f8031fad-9265-44fc-920c-f7d75ebc06b0','foreshadow','细节暗号伏笔','数字/颜色/细节暗号伏笔模板','## 埋设手法
在叙述中反复出现某个特定的数字、颜色、符号或细节。

## 常见暗号
### 数字暗号
- 某个数字反复出现（如"九"——九重天、九转、九死一生）
- 谜语中的数字实际暗示地理坐标/时间
- "三"的重复：三次机会、三件法宝、三个条件

### 颜色暗号
- 某个角色始终穿特定颜色（与其隐藏身份有关）
- 特定颜色代表特定势力/血脉
- 天空出现某种颜色异象的特殊含义

### 标记暗号
- 多处出现的相同符文/印记
- 看似装饰性的图案实际是阵法碎片
- 不同人身上有相同的胎记/伤疤

## 回收要点
- 当读者（或主角）把所有暗号串联起来时，真相浮现
- 这类伏笔适合推理感强的剧情
- 回收时可以做一个"蒙太奇式回忆"：闪回所有出现过暗号的场景

## 写作注意
- 暗号要自然地融入场景，不能刻意
- 至少出现3次以上才算伏笔，1-2次只是巧合','["伏笔", "细节", "暗号", "推理"]',1,'2026-04-13T09:34:28.840326+00:00','2026-04-13T09:34:28.840326+00:00');
INSERT INTO "knowledge_items" VALUES('9bd5e2af-3233-49aa-bcb5-83c2d3415107','foreshadow','反派洗白伏笔','反派洗白/反转伏笔模板','## 埋设手法
- 反派在某些时刻展现不符合"恶人"形象的行为
- 反派对某个人/某件事有异常的执着
- 反派手下偶尔透露"大人其实……"但被打断
- 反派做坏事时有不必要的"多余动作"（其实是保护某人）

## 真相设计
### 卧底型
- 反派其实是正道派来的卧底
- 做的每件"坏事"都是为了获取更大的情报
- 不得不牺牲一些人来维持伪装

### 苦衷型
- 反派的至亲被更大的恶势力控制
- 必须做恶事才能保护家人
- "你以为我愿意这样吗？"

### 大局型
- 反派看到了更大的威胁（域外入侵等）
- 通过"恶行"逼迫正道变强以应对未来危机
- "等你们足够强的时候，就会明白我今天做的一切"

## 回收时机
- 在反派倒下的瞬间揭露真相（最虐）
- 在大战前夕反派主动坦白（最震撼）
- 通过第三方线索逐步拼凑（最推理）','["反派", "洗白", "伏笔", "反转"]',1,'2026-04-13T09:34:28.840326+00:00','2026-04-13T09:34:28.840326+00:00');
INSERT INTO "knowledge_items" VALUES('84d38107-e74f-4b23-b20e-7b3f3f43b5f1','foreshadow','轮回因果伏笔','轮回因果伏笔模板','## 核心概念
前世种因，今生得果。修仙世界的因果纠缠跨越千万年。

## 埋设手法
- 主角总是被某些人莫名针对（前世仇敌转世）
- 某些人对主角莫名亲近（前世至亲转世）
- 到达某些地方感到异常熟悉
- 某些功法一学就会（前世修炼过的肌肉记忆）

## 因果线设计
### 恩因果
- 主角前世救过的人今生成了贵人
- 但对方可能不知道原因，只是"本能地想帮你"

### 仇因果
- 前世被主角所杀之人转世后成为宿敌
- 两人冥冥中被命运牵引到对立面

### 情因果
- 前世的爱侣今生再次相遇
- "我总觉得我在哪里见过你"
- 但今生的身份/立场可能完全不同

### 债因果
- 前世欠下的天道业力需要今生偿还
- 主角的某些"坏运气"其实是前世业力

## 回收方式
- 前世记忆觉醒时一切恍然大悟
- 与某人对视瞬间双方同时回忆前世
- 轮回秘境中亲眼看到前世的一切','["轮回", "因果", "前世", "伏笔"]',1,'2026-04-13T09:34:28.840326+00:00','2026-04-13T09:34:28.840326+00:00');
INSERT INTO "knowledge_items" VALUES('718ec147-6dfb-43fc-b00b-3606d2cd0d45','chapter_template','拜师章','拜师/投门章·写作模板','## 结构
1. **机缘际会**（300字）：主角偶遇隐世强者/到达宗门门前
2. **考核试炼**（500字）：资质测试/入门考验（淘汰率极高）
3. **被人轻视**（300字）：资质平平被嘲笑/师父看似不靠谱
4. **隐藏闪光**（400字）：关键环节展现特殊之处（系统/血脉/悟性）
5. **确立关系**（300字）：正式行拜师礼/获得弟子令牌
6. **留下悬念**（200字）：师父意味深长的一句话/同门中的暗流

## 拜师礼仪感
- 三叩九拜的仪式
- 师父赐名/赐法宝/传功法
- "从今天起，你就是我XX的弟子"
- 其他弟子的各种反应（嫉妒/欢迎/冷漠）

## 写作要点
- 师父的第一印象要与后续形象形成反差
- 入门考核中要暗示主角的特殊性
- 同门师兄弟的初次互动要建立关系网
- 为后续的宗门剧情埋下种子','["拜师", "入门", "考核", "模板"]',1,'2026-04-13T09:34:28.840326+00:00','2026-04-13T09:34:28.840326+00:00');
INSERT INTO "knowledge_items" VALUES('af38069a-4949-406e-aeab-5702b1767e8b','chapter_template','大决战章','终极大决战章·写作模板','## 结构
1. **战前宣言**（300字）：双方最后的对话，阐明各自信念
2. **全力爆发**（800字）：不留后手，一上来就是终极招式
3. **攻防转换**（600字）：互有胜负，双方都受伤
4. **回忆闪回**（300字）：战斗间隙闪过重要记忆（为何而战）
5. **绝境反击**（500字）：一方濒临极限时爆发最强一击
6. **胜负已分**（300字）：决定性的一刻
7. **战后余韵**（200字）：胜负双方的最后对话/旁观者反应

## 描写层次
- 物理层：招式碰撞、环境毁灭
- 能量层：法则交锋、天地变色
- 精神层：道心碰撞、信念对决
- 情感层：恩怨了结、释然或遗憾

## 终极对决的特殊要求
- 不能一边倒，即使主角赢也要付出巨大代价
- 反派在最后时刻要展现人性的一面
- 战后的沉默比欢呼更有力量
- 不要打完立刻跳到下一件事，给读者消化时间','["决战", "终极", "BOSS", "模板"]',1,'2026-04-13T09:34:28.840326+00:00','2026-04-13T09:34:28.840326+00:00');
INSERT INTO "knowledge_items" VALUES('24e4f360-7cb6-47e3-a9de-5fd855f1e565','chapter_template','谈判交易章','谈判/交易/外交章·写作模板','## 结构
1. **情报准备**（200字）：主角了解对方底牌和需求
2. **场面话**（200字）：双方寒暄，暗中试探
3. **开价与还价**（400字）：提出条件，唇枪舌剑
4. **僵局**（300字）：谈判陷入僵持，气氛紧张
5. **杀手锏**（300字）：主角亮出对方不知道的底牌/情报
6. **达成协议**（200字）：双方妥协，各取所需
7. **暗手布置**（100字）：协议之外的暗中安排

## 谈判类型
- **势力结盟**：面对共同敌人的利益交换
- **资源交易**：以稀有材料换取情报/支持
- **人质谈判**：营救被困同伴的紧张博弈
- **投降谈判**：战败方的最后尊严

## 写作技巧
- 通过对话展示双方的智商和格局
- 谈判中的每个条件都要有逻辑支撑
- 穿插回忆/内心独白揭示真实想法
- 不是所有谈判都成功，破裂的谈判更有张力','["谈判", "交易", "外交", "模板"]',1,'2026-04-13T09:34:28.840326+00:00','2026-04-13T09:34:28.840326+00:00');
INSERT INTO "knowledge_items" VALUES('afd6d1ba-5e22-4caa-918d-aacbc4b3323d','chapter_template','收服章','收服/降服章·写作模板','## 结构
1. **强者出场**（300字）：展示被收服对象的实力和桀骜
2. **正面对决**（500字）：先打一场，建立实力认知
3. **心理瓦解**（300字）：揭示对方的弱点/困境/渴望
4. **给出答案**（300字）：主角提供对方无法拒绝的方案
5. **臣服时刻**（200字）：对方认可主角，宣誓效忠
6. **团队融入**（200字）：与现有团队成员的互动

## 适用对象
- 桀骜不驯的修士高手
- 高阶灵兽/妖族
- 散修团伙/佣兵小队
- 曾经的对手/敌方将领

## 收服说服术
- "我不需要奴仆，我需要同伴"
- "跟着我，你想要的我都能给你"
- 用实力征服 → 用人格魅力巩固
- 给对方在团队中的独特定位（军师/先锋/暗卫）

## 写作注意
- 收服不能太快太轻易
- 被收服者不能丧失个性变成应声虫
- 收服后要给对方高光时刻证明自己的价值','["收服", "降服", "团队", "模板"]',1,'2026-04-13T09:34:28.840326+00:00','2026-04-13T09:34:28.840326+00:00');
INSERT INTO "knowledge_items" VALUES('c830729d-d2b5-44e3-ba1a-68e5895f50c0','chapter_template','宴会社交章','宴会/峰会/社交章·写作模板','## 结构
1. **盛装出席**（200字）：主角低调或高调抵达（取决于当前身份）
2. **各方亮相**（300字）：介绍在场的重要人物和势力
3. **暗流涌动**（400字）：表面觥筹交错，实则各怀鬼胎
4. **冲突引爆**（400字）：有人故意挑事/揭露秘密/发起挑战
5. **主角应对**（300字）：化解危机或借势立威
6. **结盟/树敌**（200字）：社交成果，收获盟友或得罪人

## 社交场合类型
- **宗门峰会**：各宗门掌门齐聚议事
- **拜寿宴**：某位大能寿诞，各方送礼
- **庆功宴**：战后庆祝，论功行赏
- **订婚宴/道侣仪式**：喜事变故事导火索

## 宴会爽点
- 别人不知道主角身份时被怠慢 → 身份曝光后全场变脸
- 宴席上的文斗/武试 → 主角碾压全场
- 收到的"垃圾"礼物被主角识破是极品宝物

## 信息密度
宴会章是信息量最大的章节类型，可以自然地：
- 介绍新角色、展示势力格局
- 埋设伏笔、推进支线
- 展现主角的社交智慧（不只是打打杀杀）','["宴会", "社交", "峰会", "模板"]',1,'2026-04-13T09:34:28.840326+00:00','2026-04-13T09:34:28.840326+00:00');
INSERT INTO "knowledge_items" VALUES('cfdb77c3-88d3-4490-b07c-f691157b2826','writing_technique','对话写作','修仙小说对话写作技巧','## 对话的三个功能（每句对话至少满足一个）
1. **推进剧情**：传递新信息、触发新事件
2. **展现性格**：通过说话方式展示角色身份和性格
3. **制造冲突**：对话中的交锋产生矛盾和张力

## 不同身份的说话方式
- **老一辈强者**：言简意赅，喜欢用"嗯""你且去吧"
- **世家纨绔**：嚣张跋扈，"你知道我爹是谁吗"
- **主角**：前期沉默寡言，后期从容淡定
- **军师型**：引经据典，说话留三分余地
- **热血配角**：大嗓门，"干就完了！"
- **长辈/师父**：点到为止，"悟了多少看你自己"

## 修仙特有的对话元素
- 境界称呼："前辈""道友""晚辈""老祖"
- 威胁话术："你可想清楚，得罪XX宗的后果"
- 交易话术："此物价值千金，道友可愿意以XX交换？"
- 传道话术："大道三千，你走的是哪一条？"

## 常见错误
- 所有人说话方式一样（没有区分度）
- 对话太长变成演讲
- 为了解释设定写大段对白（用情节代替）
- 现代感太强（修仙者不会说"OK""没毛病"）','["对话", "写作", "技巧", "语言"]',1,'2026-04-13T09:34:28.840326+00:00','2026-04-13T09:34:28.840326+00:00');
INSERT INTO "knowledge_items" VALUES('bd303152-9ae1-4777-9314-87d0a5d8c1e0','writing_technique','环境描写','修仙世界环境描写技巧','## 核心原则
环境描写不是装饰，而是服务于情节和情感。

## 环境描写的三个作用
1. **营造氛围**：通过环境暗示即将发生的事件
2. **展示世界观**：通过景物描写自然交代修仙世界的设定
3. **映射情感**：用环境变化反映角色心理状态

## 修仙世界特有景观
- **灵气可视化**：灵气如雾如瀑如河流
- **天象异变**：修士突破时天地变色、雷云聚集
- **灵脉地貌**：灵山秀水、灵矿发光、灵泉涌动
- **飞行视角**：御剑飞行时俯瞰的壮阔景色
- **秘境异象**：空间扭曲、重力异常、时间流速不同

## 四季与修仙的结合
- **春**：灵植破土、灵气复苏，适合修炼/播种章节
- **夏**：雷暴频繁、灵气暴动，适合战斗/渡劫章节
- **秋**：万物萧索、灵气沉降，适合转折/离别章节
- **冬**：天地封冻、灵气内敛，适合闭关/沉淀章节

## 写作注意
- 环境描写控制在3-5句以内，不要大段写景
- 每次描写都要有新信息或情感变化
- 战斗中的环境变化可以侧面烘托战斗激烈程度','["环境", "描写", "景物", "技巧"]',1,'2026-04-13T09:34:28.840326+00:00','2026-04-13T09:34:28.840326+00:00');
INSERT INTO "knowledge_items" VALUES('402d1745-3a32-4c16-aed6-4942c8d47f51','writing_technique','心理描写','角色心理描写技巧','## 心理描写方式

### 直接描写（内心独白）
"他心中一沉，一股不祥的预感涌上心头。"
→ 简单直接，适合快节奏段落

### 间接描写（通过行为暗示）
"他的手指不自觉地攥紧了袖中的玉佩。"
→ 更高级，让读者自己体会

### 环境映射
"天空阴沉得像要塌下来，和他此刻的心情一模一样。"
→ 适合重要的情感节点

### 对比反衬
"周围的欢呼声震耳欲聋，他却觉得世界安静了。"
→ 制造强烈的情感冲击

## 不同情境的心理描写

### 战前紧张
- 不写"他很紧张"，写具体的生理反应
- "手心微微出汗""呼吸不自觉加快""瞳孔微缩"

### 突破兴奋
- 不写"他很高兴"，写灵气/身体的变化感受
- "每一个毛孔都在欢呼""灵力在经脉中奔涌如潮"

### 痛失至亲
- 不写"他很悲伤"，写反常的冷静或崩溃的细节
- "他站在那里，平静得不像话。然后，膝盖弯了。"

## 避免的错误
- 过度心理描写（战斗中突然来一大段内心戏）
- 心理和行为不一致
- 所有角色的内心独白风格一样','["心理", "描写", "内心", "技巧"]',1,'2026-04-13T09:34:28.840326+00:00','2026-04-13T09:34:28.840326+00:00');
INSERT INTO "knowledge_items" VALUES('10d9c586-b1a8-4cba-bc20-eea02c5f8355','writing_technique','叙事视角','网文叙事视角控制技巧','## 主流视角选择

### 第三人称限制视角（最推荐）
- 跟随主角视角，读者只知道主角知道的
- 偶尔切到配角视角（不超过全文20%）
- 优点：代入感强，可以设悬念

### 全知视角（慎用）
- 可以展示任何角色的想法
- 优点：信息量大，适合群像
- 缺点：代入感弱，容易散

### 多视角轮转
- 每章固定一个视角角色
- 适合群像流和权谋流
- 需要每个视角角色都有吸引力

## 视角切换技巧
- 以分割线或空行明确标示切换
- 切换后第一句就要明确"谁在看/想"
- 不要在紧张时刻突然切走（除非故意制造悬念）
- 单章内视角切换不超过2次

## 视角与信息控制
- 读者知道而主角不知道 → 紧张感（"他不知道背后有人！"）
- 主角知道而其他角色不知道 → 期待感（"等他们看到主角实力的时候…"）
- 所有人都不知道 → 悬念感（"这背后到底是谁？"）

## 网文特殊处理
- 系统消息可以打破视角限制（直接展示信息）
- 反派密谋章节可以临时切换到反派视角
- 但主角戏份不能少于60%，否则读者会流失','["视角", "叙事", "POV", "技巧"]',1,'2026-04-13T09:34:28.840326+00:00','2026-04-13T09:34:28.840326+00:00');
INSERT INTO "knowledge_items" VALUES('1187d487-0c99-4e76-a717-12b6b0e54c3b','writing_technique','节奏控制','网文章节节奏控制大全','## 节奏类型

### 快节奏（紧凑型）
- 短段落、短句子
- 大量动词，少量形容词
- 事件密集，信息量大
- 适用：战斗、追逐、逃亡、危机

### 慢节奏（舒缓型）
- 长段落、长句子
- 环境描写、心理描写多
- 信息量少但情感厚度大
- 适用：修炼、感情、日常、回忆

### 中节奏（标准型）
- 长短交替
- 对话与描写混合
- 有信息推进也有情感铺垫
- 适用：剧情推进、探索、调查

## 章节节奏编排模板

### 一章3000字的黄金节奏
- 前500字：承接上文 + 本章引子
- 中1000字：主体内容（战斗/修炼/对话）
- 中800字：转折或深化
- 后500字：章末高潮/钩子
- 最后200字：留悬念收尾

### 多章节节奏编排
快→慢→快→中→快→慢（大高潮后必须缓冲）

## 断章技巧
- 在最紧张的时刻断章（读者会忍不住看下一章）
- 在重大信息即将揭露前断章
- 在角色做出选择之前断章
- 不要在平淡处断章（读者可能弃书）

## 节奏陷阱
- 连续3章以上快节奏 → 读者疲劳
- 连续3章以上慢节奏 → 读者无聊
- 大战后立刻又大战 → 无法感受胜利的喜悦
- 铺垫太久不高潮 → 期待转失望','["节奏", "控制", "断章", "技巧"]',1,'2026-04-13T09:34:28.840326+00:00','2026-04-13T09:34:28.840326+00:00');
INSERT INTO "knowledge_items" VALUES('c35fc7ba-ec32-4d6c-aa5b-efde4fa540cc','world','功法命名素材','功法命名素材库·攻击类','## 剑类功法
太虚剑诀、无量剑域、万剑归宗、天罡剑阵诀、碧落黄泉剑、诛仙剑诀、苍穹一剑、
灭世剑意、断天剑气、星辰剑典、九幽剑歌、太上忘情剑、紫电青霜剑诀、混沌剑意

## 拳掌类功法
降龙十八掌、大金刚掌、玄天混沌掌、灭世神拳、星辰碎击拳、阎罗鬼手、
天崩地裂拳、混元霹雳掌、真龙九变拳、金刚不坏拳、六道轮回掌

## 指法类功法
一指断魂、佛陀金指、剑心指、天罡六阳指、破苍指、灵犀一指、
太玄指、万象归一指、玄天神指、碎星指

## 火系功法
三昧真火诀、焚天烈焰术、九阳神焰、太阳真经、赤帝焚天诀、
凤凰涅盘诀、六丁神火诀、离火真诀、大日如来火印

## 冰系功法
太阴玄冰诀、九寒冰体术、冰魄银针功、寒冰破、北冥冰心诀、
玄天冰灵诀、霜天雪地功、千里冰封术、极地玄冰经

## 雷系功法
五雷正法、天罡雷诀、紫霄神雷、九天应元雷法、引雷入体诀、
天雷滚滚、混沌雷帝诀、雷霆万钧、先天一气雷法','["功法", "命名", "素材库", "攻击"]',1,'2026-04-13T11:03:58.804000+00:00','2026-04-13T11:03:58.804000+00:00');
INSERT INTO "knowledge_items" VALUES('7634fb89-a361-428b-bac8-41ab4aea687d','world','功法命名素材','功法命名素材库·防御/辅助类','## 护体功法
金钟罩、铁布衫、不灭金身诀、混沌体炼诀、九转玄功、
龙象般若功、太上化劫诀、天罡护体气、无相金身、万法不侵诀

## 身法功法
凌波微步、踏雪无痕、一步登天术、缩地成寸、御风术、
鲲鹏展翅、影遁术、千里不留行、天遁地隐术、追星逐月步

## 神魂功法
太上忘情诀、不灭神魂术、混沌元神诀、千幻心经、读心术、
镇魂歌、灭魂大法、蚀心魔音、万象心经、大梦心经

## 炼体功法
龙象般若功、九转玄体术、不灭圣体诀、荒古圣体经、
万兽炼体术、星辰淬体法、混沌淬体诀、真龙体术

## 阵法秘术
天罡北斗阵、九宫八卦阵、诛仙剑阵、十绝大阵、
万妖锁灵阵、五行灭杀阵、乾坤大阵、九天十地大阵

## 功法命名规律
前缀（境界/属性）+ 核心词（效果/意象）+ 后缀（诀/经/术/法/功/典/诀）
例：太虚(前缀)+剑(核心)+诀(后缀)、混沌+体炼+术','["功法", "命名", "防御", "辅助"]',1,'2026-04-13T11:03:58.804000+00:00','2026-04-13T11:03:58.804000+00:00');
INSERT INTO "knowledge_items" VALUES('d7c274b8-c5ad-4ea0-a592-e743f892e72e','world','丹药命名素材','丹药命名素材库·分级大全','## 练气期用丹
聚灵丹、清心丹、培元丹、洗髓丹、开脉丹、固本丹、灵气丹、养神丹

## 筑基期用丹
筑基丹、凝元丹、混元丹、天灵丹、破障丹、化毒丹、玄灵丹、归元丹

## 金丹期用丹
凝丹散、金丹辅助丹、护丹丸、结丹灵液、固丹丹、天心丹

## 元婴期用丹
孕婴丹、化婴丹、元婴护持丹、破婴丹、凝神丹、聚婴灵液

## 高阶丹药
化神丹、渡劫丹、天劫丹、不死丹、长生丹、造化丹、混沌丹

## 疗伤丹药
回春丹、续命丹、再生丹、活血丹、接骨丹、化瘀丹、
生肌丹、复元丹、九转还魂丹、万毒不侵丹

## 特殊丹药
易容丹（改变容貌）、隐息丹（隐藏气息）、破禁丹（解除封印）、
幻心丹（制造幻象）、忘忧丹（消除情绪）、通灵丹（与灵兽沟通）、
驱妖丹（驱散妖气）、辟谷丹（不需进食）

## 丹药命名规律
效果词 + "丹/丸/散/液/膏/粉"
例：聚灵+丹、化毒+丸、凝神+液','["丹药", "命名", "分级", "素材库"]',1,'2026-04-13T11:03:58.804000+00:00','2026-04-13T11:03:58.804000+00:00');
INSERT INTO "knowledge_items" VALUES('97751001-f719-4cbc-97f0-f7bc5cd5b352','world','法宝命名素材','法宝/灵器命名素材库','## 剑类法宝
青莲剑、赤霄剑、玄铁重剑、天问剑、紫电剑、冰魄寒光剑、
落日弓残剑、七星龙渊剑、承影剑、诛仙剑、斩仙剑、陷仙剑、绝仙剑

## 钟鼎类法宝
混沌钟、东皇钟、万灵鼎、乾坤鼎、造化鼎、太极鼎、
镇妖塔、轮回塔、浮屠塔、天罡钟、苍穹钟

## 旗帜/图类法宝
诛仙阵图、山河社稷图、河图洛书、打神鞭、杏黄旗、
素色云界旗、离地焰光旗、青莲宝色旗、玄元控水旗

## 特殊法宝
储物戒指、储物袋、乾坤袋、传讯玉简、传送玉牌、
照妖镜、定海神针、芭蕉扇、风火轮、混天绫、
金刚镯、紫金葫芦、玲珑宝塔、穿云梭、隐身斗篷

## 天材地宝
龙涎草、凤凰泪、不死泉、九转灵芝、万年雪莲、
紫晶灵石、天外陨铁、混沌神泥、太阳精火石、
星辰砂、九幽冥泉水、先天灵乳、大道灵液

## 法宝命名规律
材质/属性(前缀) + 器物类型 + 可选修饰词
例：混沌(属性)+钟(器物)、青莲(意象)+剑(类型)','["法宝", "灵器", "命名", "素材库"]',1,'2026-04-13T11:03:58.804000+00:00','2026-04-13T11:03:58.804000+00:00');
INSERT INTO "knowledge_items" VALUES('2cbaf276-f580-45aa-b057-db9a74b81839','world','门派命名素材','宗门/门派命名素材库','## 正道宗门
太虚剑宗、青云门、天机阁、紫霄宫、天剑宗、万法宗、
灵宝派、清微派、正一道、全真教、昆仑派、蜀山剑派、
玄天宗、九华宗、天音寺、焚香谷、合欢派、鬼王宗

## 魔道势力
血魔宗、万鬼门、噬魂殿、幽冥教、天魔宫、毒龙窟、
血衣楼、修罗殿、黑风寨、万妖山、炼魂宗、冥河教

## 隐世势力
无名谷、桃花源、蓬莱仙岛、瀛洲仙府、方丈山、
隐仙谷、避世山庄、太古洞天、混沌秘境

## 商业/中立势力
万宝楼、天机商会、千金坊、灵宝阁、丹王殿、
万药楼、拍卖行、赏金殿、消息阁、百宝斋

## 家族势力
上古四大家族、修仙世家、皇室暗卫、
隐世古族、远古遗族、混血家族

## 门派命名规律
- 地名/意象 + 宗/门/派/阁/殿/宫/教/寺/谷/楼
- 正道偏向：清、玄、天、灵、太、紫
- 魔道偏向：血、魔、幽、冥、噬、毒
- 中立偏向：万、百、千、金、宝','["门派", "宗门", "命名", "素材库"]',1,'2026-04-13T11:03:58.804000+00:00','2026-04-13T11:03:58.804000+00:00');
INSERT INTO "knowledge_items" VALUES('3f2c7fef-b024-42a3-8a51-6ad22a2aab0b','character','人名命名素材','修仙小说人名命名素材库','## 男主角常用名（大气/冷酷）
叶辰、苏尘、林风、陆沉、萧炎、萧尘、唐昊、韩立、
秦尘、楚天、白夜、墨渊、云澈、凌霄、顾北、沈无忧

## 女主角常用名（灵动/清冷）
苏若雪、林婉清、慕容雪、唐婉、叶灵汐、洛神、
颜如玉、楚嫣然、白浅、凤九、上官婉儿、柳如烟

## 反派常用名（阴鸷/霸道）
司徒恨天、独孤灭、血无极、天邪子、冥帝、
鬼王、阎罗、魔尊、噬天、墨千殇、慕容离

## 配角常用名（朴实/特色）
铁柱、大牛、胖子、老李、阿福、小翠、二狗子（搞笑配角）
李长老、王掌教、张真人、刘师叔（长辈型）

## 起名技巧
### 姓氏选择
- 霸气：叶、萧、慕容、独孤、上官、司徒
- 沉稳：林、韩、陆、苏、白
- 反派：冥、血、暗、鬼、魔

### 名字选字
- 阳刚：辰、尘、天、渊、昊、炎、霄
- 柔美：雪、汐、烟、兰、月、清、婉
- 神秘：玄、幽、冥、虚、无、寂、寞

### 道号/法号
真人（道教）：玄清真人、太虚真人
法师（佛门）：无相大师、明心法师
魔头（魔道）：血魔老祖、噬天魔尊','["人名", "命名", "起名", "素材库"]',1,'2026-04-13T11:03:58.804000+00:00','2026-04-13T11:03:58.804000+00:00');
INSERT INTO "knowledge_items" VALUES('30c04753-b891-4a64-b4e8-89cde0c9f1cf','world','地名命名素材','修仙世界地名命名素材库','## 大陆/大洲名
天元大陆、苍穹大陆、混沌大陆、九州大陆、玄黄大陆、
太古大陆、星辰大陆、万域大陆、浩瀚星域、无尽虚空

## 城池名
天都城、万灵城、灵宝城、玄天城、紫霄城、苍龙城、
剑灵城、丹霞城、风雷城、乾坤城、混沌城、太初城

## 山脉名
太虚山、落日山脉、龙脊山、万妖山、昆仑山、蜀山、
须弥山、灵鹫峰、天柱峰、断龙崖、绝仙崖、望天崖

## 水域名
忘川河、弱水三千、天河、冥河、灵泉、九幽泉、
天池、瑶池、龙潭、深渊、无底洞、血海

## 秘境名
太古秘境、混沌秘境、轮回秘境、天道试炼场、
万宝秘境、远古战场、仙魔古战场、上古遗迹
神都遗迹、龙族禁地、凤凰涅盘地、麒麟祖地

## 地名命名规律
- 山：属性/意象 + 山/峰/崖/岭
- 水：属性/意象 + 河/泉/海/池
- 城：属性/意象 + 城/都/府/关
- 秘境：来源/时代 + 秘境/遗迹/试炼/禁地','["地名", "命名", "城市", "素材库"]',1,'2026-04-13T11:03:58.804000+00:00','2026-04-13T11:03:58.804000+00:00');
INSERT INTO "knowledge_items" VALUES('35d2fe56-7bbb-499e-946f-66410fd545f9','writing_technique','读者心理','网文读者心理学·留存技巧','## 读者流失的三个节点
1. **前三章**（黄金三章）：决定是否继续看
2. **第15-20章**：新鲜感消退，需要第一个大高潮
3. **第50-80章**：长线疲劳，需要新地图/新势力/新目标

## 核心心理机制
### 代入感
- 读者把自己代入主角 → 主角的爽就是读者的爽
- 关键：主角前期要弱/被欺负 → 读者产生"我要变强"的欲望

### 期待感
- 埋下种子让读者期待"以后会怎样"
- 金手指的潜力暗示（"此系统仅开放10%功能"）
- 伏笔让读者猜测后续发展

### 满足感
- 定期兑现期待（爽点不能拖太久）
- 困难要有，但必须被克服
- 每次升级/打脸/获得宝物都是一次满足

### 紧张感
- 适度的危机让读者揪心
- 但不能让读者绝望（绝望=弃书）
- "虐"的尺度：虐境不虐心

## 章末钩子类型
- 悬念型："门外传来一阵脚步声——"
- 反转型："然而他不知道的是……"
- 升级型："一股更加强大的气息从他体内涌出"
- 危机型："你以为你赢了？天真。"

## 节奏黄金比例
爽:虐:日常 = 5:3:2（爽文）/ 4:4:2（热血）/ 3:4:3（深沉）','["读者", "心理", "留存", "技巧"]',1,'2026-04-13T11:03:58.804000+00:00','2026-04-13T11:03:58.804000+00:00');
INSERT INTO "knowledge_items" VALUES('e0ee55d8-3249-4ef0-af87-445f7a6518cd','writing_technique','大纲设计','网文大纲设计方法论','## 三层大纲法

### 第一层：骨架大纲（1页纸）
- 一句话概括核心故事
- 主角的起点和终点
- 3-5个关键转折点
- 结局走向

### 第二层：分卷大纲
- 每卷的核心事件和主角成长
- 每卷的主要对手
- 卷与卷之间的承接
- 伏笔的埋设和回收规划

### 第三层：章节大纲
- 每章的核心事件
- 章末钩子设计
- 出场角色和场景
- 与前后章的衔接

## "四幕结构"法
### 第一幕：起（全书1-20%）
建立世界观 → 主角出场 → 获得金手指 → 第一次冲突 → 第一次小高潮

### 第二幕：承（全书20-50%）
扩大地图 → 结识伙伴 → 实力提升 → 第一个大高潮 → 获得阶段性成功

### 第三幕：转（全书50-80%）
更大的危机 → 重大挫折/低谷 → 重新站起 → 全书最大的反转

### 第四幕：合（全书80-100%）
最终大战 → 所有伏笔回收 → 收束所有支线 → 大结局

## 剧情节奏公式
每30章一个"循环"：铺垫(10章) → 上升(10章) → 高潮+收获(5章) → 过渡(5章)','["大纲", "设计", "结构", "方法论"]',1,'2026-04-13T11:03:58.804000+00:00','2026-04-13T11:03:58.804000+00:00');
INSERT INTO "knowledge_items" VALUES('b6bd1813-aca7-4680-a7c3-3e5a7d99f5ae','writing_technique','平台规范','主流网文平台写作规范参考','## 起点中文网
- 每章字数：2000-3000字最佳，不低于1500字
- 更新频率：日更2章以上为佳
- 前三章要求：必须有明确的金手指展示和第一个小爽点
- 签约要求：通常需要3-5万字存稿

## 番茄小说
- 偏向短章节快节奏：每章1500-2500字
- 强调"黄金开篇"：第一段就要有吸引力
- 免费模式：靠广告收入，需要高留存率
- 适合：系统流、签到流等爽文类型

## 通用规范
### 章节标题
- 要有悬念感或信息量
- 好标题："第XX章 你配吗？" / "第XX章 金丹碎了"
- 差标题："第XX章 修炼" / "第XX章 战斗"

### 段落控制
- 每段不超过5行（手机阅读体验）
- 对话段落要短，一人一段
- 描写段落可以稍长但不超过8行

### 字数控制
- 每个场景500-800字
- 一章2-3个场景
- 战斗场景可以更长（1000-1500字）
- 修炼场景尽量控制在500字以内

## AI生成时的特殊注意
- 避免大段排比句（AI的典型特征）
- 减少"不禁""竟然""居然"的过度使用
- 对话后面不要每次都加"他说/她说"
- 注意同一段落不要重复使用相同词汇','["平台", "规范", "起点", "番茄"]',1,'2026-04-13T11:03:58.804000+00:00','2026-04-13T11:03:58.804000+00:00');
INSERT INTO "knowledge_items" VALUES('6e058979-aad6-474f-9d86-e38dce91fc18','world','经典体系参考','经典小说境界体系参考','## 《凡人修仙传》体系
练气 → 筑基 → 结丹 → 元婴 → 化神 → 炼虚 → 合体 → 大乘 → 渡劫 → 真仙
特色：每个境界分初/中/后/大圆满四个小阶

## 《遮天》体系
轮海 → 道宫 → 四极 → 化龙 → 仙台 → 大圣 → 准帝 → 大帝 → 仙
特色：九个大境界，每个大境界有独特的修炼方式

## 《斗破苍穹》体系
斗之气 → 斗者 → 斗师 → 大斗师 → 斗灵 → 斗王 → 斗皇 → 斗宗 → 斗尊 → 斗圣 → 斗帝
特色：每个境界1-9星，共99级

## 《诛仙》体系
入门 → 玉清境 → 上清境 → 太清境 → 天人合一
特色：境界较少但每个境界内差距巨大

## 《仙逆》体系
凝气 → 筑基 → 结丹 → 元婴 → 婴变 → 问鼎 → 碎涅 → 净涅 → 窥涅 → 天变
特色：独创"涅盘"系境界

## 自创体系建议
- 9-12个大境界最合理
- 每个大境界有3-4个小阶
- 越高的境界人数越少（金字塔结构）
- 每个境界要有标志性能力（飞行/神通/法则）','["境界", "体系", "经典", "参考"]',1,'2026-04-13T11:03:58.804000+00:00','2026-04-13T11:03:58.804000+00:00');
INSERT INTO "knowledge_items" VALUES('96eaaa5f-77b6-4d7e-a969-b611832643c8','plot','经典桥段参考','经典修仙小说必备桥段50例','## 开局桥段（前20章）
1. 废柴觉醒：天生废脉突然获得金手指
2. 退婚打脸：被退婚后逆袭
3. 穿越附身：现代人穿越到修仙世界
4. 重生归来：巅峰强者重回少年时代
5. 寒门崛起：小家族少年进入大宗门
6. 捡到宝物：路边捡到上古法宝/戒指
7. 系统降临：获得签到/商城/任务系统
8. 救人结缘：救下某人获得机缘/盟友

## 升级桥段（随时可用）
9. 宗门大比：一鸣惊人
10. 秘境探险：获得传承
11. 丹药突破：服用珍稀丹药境界暴涨
12. 战斗顿悟：生死之间领悟大道
13. 拜师学艺：获得顶级功法
14. 签到奖励：签到获得逆天物品
15. 挑战强者：越级杀敌

## 冲突桥段
16. 拍卖争夺：竞价天才地宝
17. 城门冲突：被纨绔欺负后反杀
18. 家族危机：回家救亲
19. 被人陷害：冤枉→反击→洗清
20. 仇人追杀：逃亡中变强
21. 势力冲突：宗门间的利益争斗
22. 背叛反转：亲信背叛后反杀

## 情感桥段
23. 英雄救美：战斗中救下女主
24. 同甘共苦：一起闯秘境培养感情
25. 生离死别：一方"死亡"另一方暴走
26. 误会冰释：阴差阳错后真相大白
27. 师徒情深：师父牺牲护弟子

## 高潮桥段
28. 渡劫飞升：终极突破
29. 域外大战：抵御外敌入侵
30. 一人灭宗：单挑整个敌对势力
31. 身份曝光：隐藏身份大揭露
32. 终极对决：与宿敌的最终之战','["桥段", "经典", "必备", "参考"]',1,'2026-04-13T11:03:58.804000+00:00','2026-04-13T11:03:58.804000+00:00');
INSERT INTO "knowledge_items" VALUES('74b288d6-bd99-449a-be67-65ff29b1d40c','satisfying','经典金句素材','修仙小说经典金句/台词素材库','## 霸气宣言类
- "三十年河东三十年河西，莫欺少年穷！"——萧炎
- "我命由我不由天！"
- "顺我者昌，逆我者亡。"
- "这天，我要它再也遮不住我的眼；这地，我要它再也束不了我的心。"
- "今日我以命证道，纵万劫不复，亦无悔！"

## 护短霸气类
- "动他一根头发，我灭你满门。"
- "他是我的人，你配碰吗？"
- "在我面前，谁敢动我的兄弟？"
- "你可以侮辱我，但不能侮辱我身后的人。"

## 装逼淡定类
- "这点实力……也配？"
- "你很强，但还不够。"
- "好久没遇到能让我出第二招的人了。"
- "你以为这就是我的全力吗？天真。"
- "弱，太弱了。"

## 悲壮深情类
- "若有来世，我定不负你。"
- "师父走了，但师父教给我的道，我会一直走下去。"
- "我用一生修行，只为这一剑——送你归天。"
- "我可以死，但我身后的人不能。"

## 反派名言类
- "正道？不过是胜者的遮羞布。"
- "弱者没有选择的权利。"
- "你以为你站在正义的一方？那只是因为你从未站在高处看过。"
- "等你有了我这样的力量，你会做出同样的选择。"

## 使用建议
- 金句要在关键时刻使用，不能每章都有
- 要符合角色性格，不能所有人都说霸气语录
- 原创 > 套用，但可以借鉴句式结构','["金句", "台词", "名言", "素材库"]',1,'2026-04-13T11:03:58.804000+00:00','2026-04-13T11:03:58.804000+00:00');
INSERT INTO "knowledge_items" VALUES('816be526-e4d7-4fbb-a8e4-b9a1870133bb','writing_technique','系统设计','系统流·外挂系统设计方法论','## 系统设计六要素
1. **获取方式**：穿越自带/濒死激活/偶然拾取/血脉觉醒
2. **核心功能**：签到/商城/任务/鉴定/合成/抽奖
3. **货币体系**：积分/贡献点/灵石/经验值
4. **升级机制**：系统本身如何变强（解锁新功能）
5. **限制条件**：冷却时间/等级限制/材料消耗
6. **成长曲线**：前期大方→中期平稳→后期需要努力

## 主流系统类型详解

### 签到系统
- 核心：每日签到获奖励，不同地点奖励不同
- 关键设计：危险地点签到奖励更丰厚（驱动剧情）
- 爽点来源：连续签到加成、隐藏签到点

### 商城系统
- 核心：花积分买功法/丹药/法宝
- 关键设计：商品定期刷新、有隐藏商品
- 爽点来源：限时打折、稀有商品上架

### 鉴定系统
- 核心：扫描物品显示真实信息
- 关键设计：鉴定等级决定信息详细度
- 爽点来源：废品鉴定出逆天宝物

## 系统的"人格化"趋势
- 冷漠系统："宿主，任务失败，扣除100积分。"
- 毒舌系统："宿主的实力真是……让人叹为观止。"
- 暖心系统："宿主加油！系统永远支持你！"
- 腹黑系统："恭喜宿主获得''全场最菜''成就。"

## 平衡性设计
- 系统给的永远比主角需要的少一点点
- 关键时刻系统掉链子（制造紧张感）
- 系统有bug/限制（不能无敌）
- 后期系统开始有对手（反系统/同类系统）','["系统", "外挂", "设计", "方法论"]',1,'2026-04-13T11:03:58.804000+00:00','2026-04-13T11:03:58.804000+00:00');
INSERT INTO "knowledge_items" VALUES('c58bdae2-6051-45ec-8a66-2e4277a0a7d6','writing_technique','竞品分析','起点月票榜·传统修仙流爆款套路分析','## 起点传统修仙流Top10共性

### 开局模式（前30章）
- **凡人流**：主角无背景，靠自己一步步修炼（《凡人修仙传》模式）
  → 前10章必须展示主角的"聪明"和"果断"，弥补金手指不足
- **重生流**：巅峰强者重回少年（《仙逆》模式）
  → 前3章必须展示前世记忆带来的信息差优势
- **机缘流**：偶得上古传承/器灵（《遮天》模式）
  → 前5章必须展示金手指的独特性和成长潜力

### 中期节奏（30-200章）
- 每50章换一个"地图"（宗门→城市→秘境→新大陆）
- 每30章至少一次越级战斗
- 每20章一个新的重要配角登场
- 每100章一次大高潮（宗门大比/秘境探险/势力大战）

### 长线布局
- 伏笔密度：每10章至少埋1个伏笔，50章内回收
- 反派梯队：小反派(10章)→中反派(50章)→大反派(200章)→终极BOSS
- 势力升级：小门派→一流宗门→圣地→上界
- 女主出场节奏：第一女主前30章必须出场

### 起点读者偏好
- 偏好"谋略感"：主角要有算计，不是纯莽
- 偏好"厚重感"：世界观要大，历史要深
- 对文笔要求较高：描写要有层次，不能太白
- 月票冲刺期（月初/月末）需要安排大高潮','["竞品", "起点", "传统修仙", "爆款分析"]',1,'2026-04-16T09:59:02.055216+00:00','2026-04-16T09:59:02.055216+00:00');
INSERT INTO "knowledge_items" VALUES('55dac872-0270-45ce-8372-769ff190cda5','writing_technique','竞品分析','番茄小说·签到/系统流爆款套路分析','## 番茄爆款核心数据
- 留存率决定一切：第1章留存>60%才有推荐
- 完读率>40%才能进入大推荐池
- 最佳章节长度：1500-2000字/章

### 签到流爆款公式
**第1章**：主角获得签到系统 → 第一次签到获得逆天奖励 → 被人看不起
**第2章**：用签到奖励小露一手 → 旁人震惊 → 更大的人来了
**第3章**：连续签到加成 → 第一个小高潮 → 暴露后被追/被拉拢

### 系统流关键设计
- **商城系统**：每10章刷新一次商城，必有1件让读者眼馋的限时商品
- **签到系统**：不同地点不同奖励 → 驱动主角去危险地点 → 推动剧情
- **任务系统**：主线任务+支线任务+隐藏任务三层 → 永远有事做
- **抽奖系统**：保底机制+SSR概率 → 每次抽奖都是爽点

### 番茄读者偏好
- 节奏要快：3章一个小爽点，10章一个大爽点
- 装逼打脸要密集：每5章至少一次打脸
- 系统提示要格式化：用【】框起来，读者看到就兴奋
- 不需要太深的世界观，够用就行
- 喜欢"数值碾压"：直接用数字对比实力差距

### 数据对比
| 指标 | 起点传统流 | 番茄签到流 |
|------|-----------|-----------|
| 章均字数 | 2500-3000 | 1500-2000 |
| 爽点间隔 | 15-20章 | 3-5章 |
| 伏笔深度 | 50-200章 | 10-30章 |
| 文笔要求 | 较高 | 中等偏低 |
| 世界观 | 宏大复杂 | 简洁明快 |
| 适合AI生成 | 需要精调 | 非常适合 |','["竞品", "番茄", "签到流", "系统流", "爆款分析"]',1,'2026-04-16T09:59:02.055216+00:00','2026-04-16T09:59:02.055216+00:00');
INSERT INTO "knowledge_items" VALUES('60898d15-4b76-4629-ad69-d2f18f6f6ddf','world','神通命名素材','神通/大招命名素材库','## 空间类神通
大挪移术、缩地成寸、须弥芥子、虚空破碎、空间封锁、
乾坤一掷、界壁穿梭、虚空藏、空间折叠术、次元斩

## 时间类神通
时光回溯、岁月长河、光阴倒流、时间凝固、
沧海桑田一念间、时间加速域、永恒静止

## 生死类神通
万物枯荣、生死逆转、枯木逢春、灭世之瞳、
黄泉召唤、轮回之眼、死气灌顶、大寂灭术

## 天象类神通
呼风唤雨、移山填海、翻天覆地、日月无光、
星辰坠落、天河倒灌、陨石召唤、天地同寿

## 佛道类神通
如来神掌、大日如来印、不动明王法身、金刚不坏、
般若波罗蜜、天龙八部阵、六道轮回、大威天龙

## 魔道类神通
九幽噬魂、血海滔天、万鬼夜行、天魔解体大法、
噬天魔功、幽冥鬼火、百鬼夜行图、修罗血屠

## 命名公式
[属性/来源] + [效果/意象] + [术/印/诀/法/功]
高阶加前缀：大、太、无上、混沌、先天、亘古','["神通", "大招", "命名", "素材库"]',1,'2026-04-16T09:59:02.055216+00:00','2026-04-16T09:59:02.055216+00:00');
INSERT INTO "knowledge_items" VALUES('650885e0-d50e-4c45-bdca-48391f5ead9f','world','称号命名素材','称号/封号/异名命名素材库','## 战力型称号
剑魔、刀圣、拳皇、枪神、杀神、战狂、不败战神、
万人屠、血修罗、人间凶器、同阶无敌、一剑破万法

## 身份型称号
丹帝、阵祖、器圣、符神、药王、鬼医、
万宝之主、灵植大师、驭兽宗师、傀儡大师

## 境界型称号
人仙、地仙、天仙、金仙、太乙、大罗、准圣、
渡劫散仙、半步真仙、伪仙、破境者

## 势力型称号
宗主、掌教、门主、城主、域主、帝君、天帝、
圣子/圣女、真传弟子、核心弟子、首席长老

## 异名/绰号型
- 冷酷型：冰皇、孤剑客、绝情道人、冥王
- 霸气型：天下第一、无双、帝临、苍生主宰
- 神秘型：无名氏、面具人、黑袍客、幕后之人
- 搞笑型：赌王（赌石高手）、药罐子（常吃丹药）

## 称号获取节奏
前期：被嘲讽的外号（废物、笑柄）
中期：实力认可的称号（某某第一、某某之最）
后期：威震天下的异名（某某魔帝、某某剑尊）
终章：传说中的名字（千年后仍被传颂）','["称号", "封号", "异名", "命名"]',1,'2026-04-16T09:59:02.055216+00:00','2026-04-16T09:59:02.055216+00:00');
INSERT INTO "knowledge_items" VALUES('e0315dd0-bec5-4c46-8e39-bd98f176841f','world','灵兽命名素材','灵兽/神兽/妖族命名素材库','## 上古神兽（传说级）
青龙、白虎、朱雀、玄武、麒麟、凤凰、
鲲鹏、貔貅、白泽、饕餮、梼杌、穷奇、混沌

## 龙族分支
蛟龙、螭龙、虬龙、应龙（有翼）、烛龙（开目为昼闭目为夜）、
龙龟、冰龙、火龙、雷龙、暗龙、骨龙、龙马

## 凤族分支
火凤、冰凰、九彩鸾凤、金翅大鹏、孔雀大明王、
三足金乌、毕方鸟、重明鸟、鸩鸟

## 灵兽（可培养）
灵狐（九尾进化）、仙鹤、灵猿、月兔、
雪狼、火鸦、雷鹰、风隼、金蚕、血蝠

## 妖族高阶
天狐（九尾天狐）、大圣（灵猿化圣）、蛇皇（化蛟前身）、
万毒蝎王、深渊巨鲸、不死火凤、万年灵龟

## 异变/融合种
龙凤兽、麒麟蚁（突变）、混沌兽、时间虫、
空间蝶、因果蛛、噬灵蚕、幻梦蝶

## 灵兽命名规律
[属性/外观] + [种族名] + 可选[王/皇/帝/尊]
例：赤焰(属性)+狮(种族)+王(等级)','["灵兽", "神兽", "妖族", "命名"]',1,'2026-04-16T09:59:02.055216+00:00','2026-04-16T09:59:02.055216+00:00');
INSERT INTO "knowledge_items" VALUES('5f7ebb6c-0ce6-4d73-aca7-3c6ab1b58ecc','world','阵法命名素材','阵法/禁制命名素材库','## 攻击型阵法
诛仙剑阵、万剑归宗阵、天火焚天阵、雷霆万钧阵、
五行灭杀阵、九宫飞星阵、七杀破军阵、灭世大阵

## 防御型阵法
护山大阵、金刚不坏阵、乾坤罩、天罡北斗阵、
玄天护法阵、万法不侵阵、混元一气阵

## 困锁型阵法
迷仙阵、困龙阵、万妖锁灵阵、八门金锁阵、
六合封禁阵、天地牢笼、虚空封印阵

## 幻术型阵法
十面埋伏阵、迷心幻境、千变幻阵、梦魇之阵、
心魔试炼阵、轮回幻境阵

## 辅助型阵法
聚灵大阵、九转聚元阵、天地灵脉引导阵、
传送阵、时间加速阵（闭关用）、炼丹辅助阵

## 上古/传说级阵法
周天星斗大阵（以星辰之力）、十二都天神煞大阵、
先天五方旗阵、两仪微尘大阵、盘古大阵

## 阵法命名规律
[属性/数量] + [意象] + [阵/禁制/结界/法阵]
数量：二仪、三才、四象、五行、六合、七星、八卦、九宫','["阵法", "禁制", "命名", "素材库"]',1,'2026-04-16T09:59:02.055216+00:00','2026-04-16T09:59:02.055216+00:00');
INSERT INTO "knowledge_items" VALUES('7cb7f956-a9c2-4006-964e-6cb71a2399ac','world','种族命名素材','修仙世界种族命名素材库','## 先天种族（创世纪）
混沌古族、先天神族、天生万灵族、始祖巫族、
元素精灵族、时空守护族

## 仙魔种族
仙族（天庭系）、魔族（域外天魔）、妖族、鬼族（冥界系）、
佛族（西方极乐系）、魔修（人族堕落）

## 万族联盟常见种族
- 龙族：血脉高贵，化人形后仍保留龙角/龙鳞
- 凤族：火属性天赋，浴火重生
- 麒麟族：祥瑞之兆，天生亲和力
- 巫族：以巫术通天地，肉身强横
- 灵族：天生灵识强大，擅长精神攻击
- 石族：身躯坚不可摧，寿命极长
- 树族/花族：通灵灵植化形
- 虫族：数量恐怖，集群智慧

## 域外种族（反派常用）
天魔族、虚空虫族、混沌兽族、暗影族、
血族（吸取修为）、傀儡族（以他者躯壳为生）

## 种族命名规律
[特征/属性] + 族/一族/氏
高贵感：某某皇族、某某神族、某某古族
野蛮感：某某蛮族、某某兽族、某某虫族','["种族", "万族", "命名", "素材库"]',1,'2026-04-16T09:59:02.055216+00:00','2026-04-16T09:59:02.055216+00:00');
INSERT INTO "knowledge_items" VALUES('a0ab25f5-6a46-4df6-bee1-87d4f6b14274','world','毒术体系','毒道·毒术与毒物体系大全','## 毒修境界
识毒（认识毒物）→ 炼毒（炼制毒药）→ 用毒（以毒攻敌）→ 化毒（百毒不侵）→ 毒道（万毒归一）

## 毒物分级
- 凡毒：七步断肠散、鹤顶红、见血封喉 → 对凡人致命，修士可抵抗
- 灵毒：腐骨阴风毒、蚀心蛊、三尸虫 → 金丹以下难解
- 宝毒：九幽冥毒、天蚕毒丝、噬魂蛊王 → 元婴期也会中招
- 圣毒：混沌毒雾、万毒之源、天地瘴气 → 化神期以上才能抵御
- 仙毒：灭世毒莲、太古毒龙涎 → 传说级，可毒杀仙人

## 用毒方式
- 下毒入食/水源（最基础）
- 毒雾/毒阵（区域控制）
- 蛊术（活体寄生，远程控制）
- 毒功（将毒素融入灵力攻击）
- 瘟疫术（大范围扩散，禁术级别）

## 解毒体系
- 万毒珠：吸收毒素的法宝
- 至阳真气：以纯阳之力净化毒素
- 以毒攻毒：用更强的毒中和
- 灵泉/圣水：天然解毒之物
- 解毒丹药：对症下药（需要识别毒种）

## 叙事价值
- 毒修是天然的"诡道"角色，适合做反派或亦正亦邪配角
- 主角中毒是绝佳的危机制造手段
- 解毒过程本身就是一条剧情线
- 毒修在战斗中的战术多样性很高','["毒术", "毒物", "蛊术", "体系"]',1,'2026-04-16T09:59:02.055216+00:00','2026-04-16T09:59:02.055216+00:00');
INSERT INTO "knowledge_items" VALUES('0b2a62f0-7a57-44db-9847-9a83e88c42bb','world','符箓体系','符箓·符文与铭文体系大全','## 符箓分类
### 按用途
- 攻击符：火符、雷符、冰锥符、剑气符
- 防御符：金光护体符、避邪符、金刚符
- 辅助符：隐身符、千里传音符、定位符、净化符
- 禁制符：封印符、禁言符、困兽符
- 特殊符：替死符（替主人挡一次致命攻击）、契约符、空间符

### 按品质
黄符（练气级）→ 蓝符（筑基级）→ 紫符（金丹级）→ 金符（元婴级）→ 仙符（传说级）

## 制符流程
1. 选材：符纸（妖皮/灵木/金箔）+ 符墨（灵兽血/灵液）
2. 刻画：以神识引导灵力，在符纸上画出符文
3. 灌注：注入灵力激活符文
4. 封存：以特殊手法封住灵力防止流失

## 符师等级
一品符师（画黄符）→ ... → 九品符宗（画仙符）

## 铭文体系（法宝刻印）
- 在法宝上刻画符文增强属性
- 铭文师比符师更稀缺
- 铭文数量决定法宝品质上限
- 传说级铭文可以让凡器蜕变为仙器

## 叙事用法
- 符箓是一次性消耗品 → 制造资源紧张感
- 制符过程有失败率 → 炼制爽点/损失冲突
- 替死符 → 绝杀反转的关键道具
- 铭文师身份 → 被各方势力拉拢的筹码','["符箓", "符文", "铭文", "体系"]',1,'2026-04-16T09:59:02.055216+00:00','2026-04-16T09:59:02.055216+00:00');
INSERT INTO "knowledge_items" VALUES('83ca2723-7ad3-4526-b131-9267a5f54672','world','双修体系','双修·道侣与双修功法体系','## 双修类型
### 阴阳双修
- 一阴一阳互补，修炼速度倍增
- 需要体质契合度高
- 经典配置：火属性男+冰属性女

### 同源双修
- 修炼同一功法的两人互相印证
- 共享修炼感悟，突破瓶颈
- 师兄妹/同门双修常见

### 契约双修
- 以血契或魂契为基础
- 一人突破另一人也能获益
- 但一人受伤另一人也会受影响

## 道侣制度
- 结为道侣 = 修仙世界的婚姻
- 道侣誓言有天道见证，背叛会遭天罚
- 道侣可共享灵脉、洞府、修炼资源
- 一方飞升可带道侣同行（条件苛刻）

## 双修功法命名
阴阳合欢功、天地交泰诀、龙凤呈祥功、
日月同辉诀、鸳鸯双栖功、太极两仪诀

## 叙事利用
- 双修是感情线和修炼线的完美结合点
- "必须找到体质契合的道侣否则功法反噬" → 驱动感情线
- 道侣一方被害 → 另一方暴走/境界跌落 → 复仇线
- 双修突破时的天地异象 → 暴露位置被偷袭

## 禁忌双修（反派常用）
- 采补术：吸取对方修为（邪功）
- 魔道合欢：以媚术控制他人
- 这类设定需要谨慎处理，点到为止','["双修", "道侣", "阴阳", "体系"]',1,'2026-04-16T09:59:02.055216+00:00','2026-04-16T09:59:02.055216+00:00');
INSERT INTO "knowledge_items" VALUES('03e72274-ae47-401f-b153-b0e9b0c1fcef','world','修仙政治','修仙世界政治体系与权力架构','## 修仙世界的权力层级
### 顶层：超级势力
- 圣地/帝级宗门（1-3家，仙人坐镇）
- 修仙帝国/皇朝（世俗政权+修士结合）
- 远古家族（万年传承，底蕴深厚）

### 中层：区域霸主
- 一流宗门（大乘/合体期掌教）
- 修仙王国
- 大型商会（万宝楼级别）

### 底层：地方势力
- 小宗门/家族
- 散修联盟
- 坊市管理组织

## 政治博弈类型
### 宗门内政
- 掌教传位之争（嫡系 vs 旁系）
- 长老会权力制衡
- 内门/外门资源分配矛盾
- 宗门叛徒/间谍

### 势力外交
- 联盟：共同应对更大威胁
- 联姻：以道侣关系绑定利益
- 朝贡：小势力向大势力纳贡求庇护
- 暗战：派人渗透对方势力

### 资源政治
- 灵脉归属之争
- 秘境开放权的分配
- 炼丹师/阵法师等稀缺人才争夺
- 灵石铸币权和经济控制

## 权谋常用套路
- 借刀杀人：挑拨两个势力互斗
- 围魏救赵：攻击对方后方迫其回援
- 釜底抽薪：切断对方资源供应
- 驱虎吞狼：引导域外敌人攻击竞争对手

## 对主角的影响
- 前期：被政治漩涡波及（被迫站队/卷入争斗）
- 中期：利用政治格局借力打力
- 后期：主导政治格局，建立新秩序','["政治", "权力", "权谋", "势力"]',1,'2026-04-16T09:59:02.055216+00:00','2026-04-16T09:59:02.055216+00:00');
INSERT INTO "knowledge_items" VALUES('a106dffd-7e9b-447f-b989-e541db85ca2b','writing_technique','AI优化','AI写作去AI感·优化技巧大全','## AI写作的典型"AI味"特征
1. **排比句过多**："他感受到了力量，感受到了自由，感受到了……"
2. **转折词滥用**："然而""不过""但是"每段都有
3. **描写空洞**：大量形容词堆砌但缺乏具体画面
4. **情感标签化**：直接说"他很愤怒"而不是展示愤怒
5. **节奏单一**：每段长度差不多，缺乏变化
6. **对话均质化**：所有角色说话风格一样
7. **万能词**："不禁""竟然""居然""仿佛"高频出现

## 去AI感的核心策略

### 1. 用具体替代抽象
❌ "他感到一阵强大的力量涌来"
✅ "丹田中的灵力猛地膨胀，撑得经脉隐隐作痛，指尖不由自主地颤抖"

### 2. 用动作替代描述
❌ "她很紧张"
✅ "她的手指无意识地绞着袖口的布料"

### 3. 打破段落均匀
- 紧张时用短句："剑来。""挡不住。""碎了。"
- 舒缓时用长句：描写环境、内心
- 刻意制造长短交替

### 4. 给每个角色"口癖"
- 老者："老夫当年……"
- 纨绔："你知道你在跟谁说话吗？"
- 系统："叮！宿主……"
- 毒舌配角："就你？算了算了。"

### 5. 删除万能词
写完后全局搜索删除/替换：
不禁→删、竟然→换具体描写、仿佛→换比喻、居然→删
一时间→删、顿时→少用、忍不住→用动作替代

### 6. 加入"废话"和口语
真人写作会有不完美的句子和停顿
"这……你确定？""行吧，那就试试。""等等，让我想想。"

## Prompt优化建议
在生成prompt中加入：
- "避免排比句，每段最多一个比喻"
- "对话要区分角色语气，老者言简意赅，年轻人语气轻快"
- "用短句表现紧张，长句表现舒缓"
- "不要使用''不禁''''竟然''''仿佛''等词"
- "每300字至少有一处五感描写（视/听/触/嗅/味）" ','["AI", "去AI感", "优化", "写作技巧"]',1,'2026-04-16T09:59:02.055216+00:00','2026-04-16T09:59:02.055216+00:00');
INSERT INTO "knowledge_items" VALUES('3a82544d-e4a6-453f-b4f9-a488c101c02d','writing_technique','多线叙事','多线叙事·交叉剧情编排技巧','## 什么时候用多线叙事
- 主角不在场但需要展示的重要事件
- 多个势力同时行动的大事件
- 需要制造信息差和悬念时
- 群像戏/势力争霸阶段

## 常见多线模式

### 双线交叉（最常用）
A线：主角线（主视角，占70%）
B线：反派/配角线（辅视角，占30%）
交替方式：A→A→B→A→A→B（不能B线太多抢戏）

### 三线并进（大事件用）
A线：主角行动
B线：盟友行动
C线：敌方行动
三线在高潮章节汇合

### 时间线交叉
现在线 + 回忆线交替
用于揭秘过去真相

## 切换技巧
### 硬切
用分割线或空行，开头直接点明新场景和新人物
"与此同时，千里之外的血魔宗——"

### 软切
通过关联词自然过渡
"他不知道的是，此刻在万里之外……"
"当那道剑光斩下的同时，另一个地方也发生了变故——"

## 多线叙事的陷阱
- B线角色没吸引力 → 读者跳着看
- 切换太频繁 → 读者晕头转向
- 各线节奏不统一 → A线高潮时切到B线日常
- 汇合点拖太久 → 读者失去耐心

## 黄金法则
- 单章内最多切换1次视角
- B线每次出场不超过全章的40%
- 每条线都要有自己的"钩子"
- 最终一定要汇合，不能无限平行','["多线", "叙事", "交叉", "编排"]',1,'2026-04-16T09:59:02.055216+00:00','2026-04-16T09:59:02.055216+00:00');
INSERT INTO "knowledge_items" VALUES('acfd623f-d7f0-4e2f-85ed-f2ad77366d92','writing_technique','节奏理论','网文节奏波浪理论·情绪曲线设计','## 波浪理论核心
读者的情绪像波浪一样起伏，好的节奏=有规律的波浪。

## 单章情绪曲线
```
高  ╱╲        ╱╲╱╲
   ╱  ╲      ╱      ╲
  ╱    ╲    ╱        ╲  ← 章末钩子（不落回谷底）
低 ╲    ╲  ╱
    ╲    ╲╱
     引入  发展  小转折  高潮  余韵
```

## 多章情绪曲线（30章一个周期）

### 第1-5章：铺垫期（谷底→缓升）
- 日常互动、信息引入、新角色出场
- 暗中埋设冲突种子
- 情绪：平静→好奇

### 第6-15章：上升期（持续攀升）
- 冲突逐步升级
- 每3章一个小爽点
- 情绪：期待→紧张→小满足

### 第16-25章：高潮期（波峰）
- 大战/大事件爆发
- 主角展现实力/智慧
- 连续爽点轰炸
- 情绪：兴奋→震撼→满足

### 第26-30章：回落期（缓降+新引子）
- 战后处理、收获盘点
- 新的伏笔/危机出现
- 为下一个周期做铺垫
- 情绪：满足→好奇→期待

## 情绪峰值管理
- 不要连续3个周期都是同一强度的高潮
- 建议：中高潮→小高潮→大高潮→喘息→超级高潮
- 全书最大高潮放在70-80%的位置
- 最后20%是收束和终极对决

## 爽点密度参考
| 小说类型 | 小爽点间隔 | 大爽点间隔 | 超级爽点间隔 |
|---------|-----------|-----------|------------|
| 爽文/签到 | 2-3章 | 10-15章 | 50章 |
| 热血/战斗 | 5-8章 | 20-30章 | 80-100章 |
| 传统修仙 | 8-12章 | 30-50章 | 100-150章 |
| 权谋/布局 | 10-15章 | 40-60章 | 120-200章 |

## "虐"的使用原则
- 虐的目的是为了让之后的爽更爽
- 虐的程度不能超过读者承受极限
- 虐完必须在5-10章内给出回报
- "虐境不虐心"：主角处境艰难但精神不能垮','["节奏", "波浪", "情绪曲线", "理论"]',1,'2026-04-16T09:59:02.055216+00:00','2026-04-16T09:59:02.055216+00:00');
INSERT INTO "knowledge_items" VALUES('64873e4d-089b-48b1-b144-35059d5d162f','writing_technique','日更技巧','高效日更·大纲与存稿管理方法','## 大纲驱动写作法

### 三级大纲工作流
1. **骨架大纲**（写书前完成，1-2页）
   - 全书主线、3-5个大转折、结局走向
   - 主角成长弧线、主要反派梯队

2. **分卷大纲**（每卷开始前完成，每卷1页）
   - 本卷核心事件、新角色、伏笔计划
   - 本卷的"小结局"

3. **章节大纲**（每周写一批，10-20章）
   - 每章1-2句：发生什么、章末钩子
   - 标注爽点、伏笔、视角切换

### 存稿策略
- 最低存稿：永远保持10章存稿
- 安全存稿：30章（可以放心请假一个月）
- 冲刺期：提前存50章用于月票冲刺加更

## AI辅助日更工作流
1. 写好章节大纲（人工，5分钟/章）
2. AI根据大纲生成初稿（自动，2-3分钟/章）
3. 人工审核修改（10-15分钟/章）
4. 润色去AI感（5分钟/章）

总计：每章20-25分钟，日更2章约1小时

## 大纲模板（AI生成用）
每章大纲应包含：
- 场景地点
- 出场角色（标注新角色）
- 核心事件（1句话）
- 冲突/爽点类型（打脸/突破/收服/剧情推进）
- 章末钩子（1句话）
- 伏笔操作（埋设/回收/提醒）
- 与前章的衔接点','["日更", "大纲", "存稿", "效率"]',1,'2026-04-16T09:59:02.055216+00:00','2026-04-16T09:59:02.055216+00:00');
INSERT INTO "knowledge_items" VALUES('91a82ba9-c4cb-438e-9e66-97d8da1f6256','plot','仙魔大战','仙魔大战·史诗级剧情模板','## 核心结构
### 序幕：裂缝初现（5-10章）
- 天地灵气异变，修士修炼受阻
- 边境出现空间裂缝，低阶魔物渗入
- 普通人开始遭殃，散修求助无门

### 第一幕：联合抵抗（10-20章）
- 各大宗门意识到危机严重性
- 召开万年未有的"修仙界联合峰会"
- 分配防线，建立联合阵法
- 主角在某一段防线上崭露头角

### 第二幕：惨烈拉锯（20-40章）
- 魔族大军压境，正面战场血流成河
- 名宿级强者陨落，读者熟悉的角色牺牲
- 叛徒出现（有人投靠魔族换取保全）
- 主角获得关键线索（魔族弱点/远古封印）

### 第三幕：绝境反攻（10-15章）
- 防线崩溃，人族退守最后堡垒
- 主角深入敌后/修复远古封印/觉醒血脉
- 一人力挽狂澜的终极之战
- 封印魔族入口/击杀魔族首领

### 尾声：战后重建（5章）
- 清点伤亡，各方势力重新洗牌
- 主角声望达到巅峰
- 新的伏笔：封印不是永久的……

## 大战场面描写要素
- 万人修士阵法 vs 魔族兽潮的全景描写
- 天空中仙人级别的法则碰撞
- 地面上普通修士的生死搏杀（小人物视角增强代入感）
- 阵法崩溃时的绝望感
- 援军到来时的狂喜','["仙魔大战", "史诗", "战争", "大事件"]',1,'2026-04-16T09:59:02.055216+00:00','2026-04-16T09:59:02.055216+00:00');
INSERT INTO "knowledge_items" VALUES('141fefdd-a007-4cbf-904e-f882511e1b9a','plot','器灵人格化','器灵/法宝人格化·剧情模板','## 器灵类型

### 上古残魂器灵
- 大能将残魂封入法宝，化为器灵
- 有前世完整记忆和人格
- 前期指导主角，后期逐渐被主角超越
- 最终可能独立化形或安然消散

### 天生器灵
- 法宝自然孕育出的灵智
- 像孩子一样逐渐成长
- 对主人有强烈的依赖感
- 进化路线：无智→灵智→器灵→化形

### 被封印者器灵
- 某个强者被封印在法宝内
- 与主角是博弈关系（想借主角之手解除封印）
- 可能是敌是友，增加悬疑感

## 器灵互动模板
- 毒舌器灵："就你这实力也配用本座？勉为其难吧。"
- 贪吃器灵：对天材地宝流口水，吃了能升级
- 傲娇器灵："才…才不是为了帮你！只是不想换主人而已。"
- 沉默器灵：平时不说话，关键时刻冒出一句关键提醒

## 成长线设计
1. 法宝被当成废铁捡到
2. 意外激活器灵，器灵嫌弃主角
3. 共同经历磨难，建立羁绊
4. 器灵逐步解锁法宝封印层
5. 最终：器灵化形/融合/传承

## 叙事价值
- 天然的"对话搭子"，独行主角也不会冷场
- 法宝升级=器灵成长，双线进步
- 器灵的秘密=大伏笔（器灵的前世/法宝的真实来历）','["器灵", "法宝", "人格化", "互动"]',1,'2026-04-16T09:59:02.055216+00:00','2026-04-16T09:59:02.055216+00:00');
INSERT INTO "knowledge_items" VALUES('c545c7a3-fbb9-4646-a39f-ed09d141c5e4','plot','秘境副本','秘境/副本设计·关卡模板大全','## 秘境类型

### 传承秘境
- 目的：获得大能传承
- 关卡：心性考验→实力考验→悟性考验→最终选择
- 特点：只能一人通过，竞争者互相淘汰

### 资源秘境
- 目的：采集天材地宝
- 结构：外围（低危低收益）→ 中层 → 核心区（高危高收益）
- 特点：有时间限制，到期自动传送出去

### 试炼秘境
- 目的：磨练实力/选拔人才
- 关卡：塔型（一层比一层难）/ 生存型（淘汰制）
- 特点：有排行榜/积分，名次越高奖励越好

### 远古战场秘境
- 目的：探索遗迹获取宝物
- 危险：残留的远古禁制/徘徊的亡灵/未熄的余火
- 特点：随机性强，可能空手而归也可能暴富

## 秘境关卡设计公式
每个关卡 = 挑战 + 奖励 + 信息
- 挑战让主角展现能力
- 奖励推动实力增长
- 信息推动剧情/揭露伏笔

## 秘境中的冲突设计
- 与其他探险者争夺资源
- 临时联盟后的背叛
- 秘境守护者/BOSS的考验
- 秘境崩塌时的逃生竞速

## 秘境节奏模板（10章）
进入+分散(2章) → 外围探索+小收获(2章) → 遭遇对手+冲突(2章) → 核心区+大BOSS(3章) → 逃出+收获盘点(1章)','["秘境", "副本", "关卡", "设计"]',1,'2026-04-16T09:59:02.055216+00:00','2026-04-16T09:59:02.055216+00:00');
INSERT INTO "knowledge_items" VALUES('33835337-4622-40f0-8f2e-d95d74c7149e','plot','商战资源','修仙世界商战/资源争夺·剧情模板','## 核心结构
1. **资源发现**：发现新灵矿/灵脉/灵田，各方觊觎
2. **暗中布局**：主角先一步掌握关键信息，暗中准备
3. **多方角力**：宗门、家族、商会、散修势力多方博弈
4. **商业战争**：价格战、囤积居奇、切断供应链
5. **武力升级**：商战谈不拢，演变为武力冲突
6. **赢家通吃**：主角以智+力胜出，获得资源控制权

## 商战手段
### 经济战
- 低价倾销：用大量低价丹药冲击对手市场
- 囤积居奇：垄断关键材料后坐地起价
- 信息战：散布假消息操纵市场价格

### 人才战
- 挖角对方炼丹师/阵法师
- 收买对方内部人员
- 联合中立势力孤立对手

### 武力威慑
- 雇佣修士保护商队
- 暗中截杀对方运输队
- 正式下战书抢夺地盘

## 主角的商业天赋展现
- 用现代商业思维降维打击（穿越者优势）
- 系统鉴定发现被低估的资源
- 以炼丹/炼器技术为核心竞争力
- 建立品牌信誉（"XX出品必属精品"）

## 叙事价值
- 展现主角不只会打架还有头脑
- 积累后续大战的资源基础
- 结识商界人脉为后续剧情铺路
- 建设流读者最爱的"经营感"满足','["商战", "资源", "经营", "争夺"]',1,'2026-04-16T09:59:02.055216+00:00','2026-04-16T09:59:02.055216+00:00');
INSERT INTO "knowledge_items" VALUES('d4c38544-2397-47be-a3ee-c9ab18bc10a1','world','故事背景参考','竞品参考·故事背景标签大全（71项）','## 故事背景标签（来自全民作家平台公开数据）

### 修仙/玄幻类
修仙世界、上古神话、远古洪荒、修真门派林立

### 古代类
古代江湖、古代王朝、架空历史、商周、秦汉、唐宋、盛唐、北宋、架空古代、朝堂

### 现代类
现代校园、都市娱乐、商业职场、现实生活

### 末世/科幻类
末世基地市、废土沙漠、灵气枯竭世界、未来星际历、近未来、机械城邦

### 异世界类
平行时空、女尊男卑、abo世界、兽人部落、精灵森林、亡灵国度

### 种族/文明类
虫族蜂巢文明、魔法学院制、封建贵族社会、修真文明、魔法文明、
科技修真融合、虫族文明、机械文明、精灵文明、矮人锻造文明、
亡灵魔法文明、共生体文明

### 特殊设定类
赛博都市、奴隶制王朝、深海秘境、异能者公会、
兽世生存、野外、迷雾环境、江湖

*数据来源: 全民作家平台公开API*','["故事背景", "标签", "竞品", "全民作家"]',1,'2026-04-16T10:36:39.389518+00:00','2026-04-16T10:36:39.389518+00:00');
INSERT INTO "knowledge_items" VALUES('b88bef73-8598-4c1b-b383-01c63decc6f6','plot','故事元素参考','竞品参考·故事元素标签大全（114项）','## 故事元素标签

### 热门流派
直播文、聊天群文、灵气复苏、废土末世、逆袭打脸、悬疑探案、
末日求生、无限流闯关、快穿任务、系统签到、秘境探险

### 感情向
甜宠无虐、双向救赎、相爱相杀、师徒恋、伪骨科、双洁文

### 权谋/宫斗
权谋斗争、迪化文、幕后流、种田文

### 流派组合（热门复合标签）
修仙+系统、科幻+言情、古风+探案、校园+异能、末世+基建、
西幻+恋爱、星际+甜宠、民国+悬疑、现代+灵异、娱乐圈+爽文

### 修仙特有元素
魂穿、魄夺、心劫、灵契、神降、魔怔、妖变、鬼探、仙途、
佛劫、道心、武炼、器灵、阵师、符尊、蛊王、医毒、商战

### 生存/冒险类
逃荒、屯物资、成长、求生、野外生存、团队协作、智斗、资源争夺、迷雾生存

*数据来源: 全民作家平台公开API*','["故事元素", "标签", "流派", "竞品"]',1,'2026-04-16T10:36:39.389518+00:00','2026-04-16T10:36:39.389518+00:00');
INSERT INTO "knowledge_items" VALUES('92a3156e-a0b7-4544-95e0-111148e13510','plot','情节标签参考','竞品参考·情节标签大全（80项）','## 情节标签

### 核心桥段
逆袭打脸、重生复仇、穿书自救、咸鱼翻身、扮猪吃虎、打脸、真假千金

### 感情桥段
死对头、替身文学、暗恋、青梅竹马、一见钟情、双向奔赴、
先婚后爱、先婚后爱（伪）、闪婚、离婚后、替嫁、隐婚、
二婚、错嫁、逃婚、契约婚姻、单暗恋、多角恋

### 宫廷/家族
宫斗、宅斗、读心、致富、替身、契约

### 升级/冒险
空间、系统、灵魂互换、金手指、异能、灵异、打怪升级、盗墓、
修仙、女性觉醒

### 职业/生活
小众职业养成、白月光、性转校园、娱乐圈、美食、
